import type { Drill } from "./types";

// Mid-career (people manager) drills, keyed by module slug — 25 per module.
// Pitched at managers: feedback, delegation, running meetings, cross-functional
// persuasion, hard conversations with reports, reporting up to leadership.
// Merged into course.ts.
export const MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-mid-01","level":"mid","title":"The buried leadership update","scenario":"Your VP asked for a quick read on your team's quarter. Two of your three goals are on track; the third slipped because a partner team deprioritized a dependency. You have a workaround that recovers most of the gap.","task":"Write a 3-5 sentence update to your VP that leads with the overall verdict before any detail.","tips":["Open with the one-line answer: are you on track for the quarter or not?","Don't start with the partner team's story — that's support.","Name the one risk and your plan for it in a single sentence."],"focus":["structure","clarity"],"placeholder":"We'll hit 2 of 3 quarterly goals; the third is recoverable. Here's the picture..."},
    {"id":"lead-mid-02","level":"mid","title":"Decision memo to your team","scenario":"After weeks of debate, you've decided your team will standardize on one ticketing tool and retire the two others. Some engineers preferred the tools being cut. You're announcing the decision in a team channel.","task":"Write the opening of the announcement so the decision lands in the first sentence, not after the rationale.","tips":["State the decision first; reasons come after.","Don't soften it into a question — it's decided.","Acknowledge the tradeoff briefly, but only after the headline."],"focus":["clarity","impact"],"placeholder":"Starting next sprint we're standardizing on Jira and retiring Trello and Linear."},
    {"id":"lead-mid-03","level":"mid","title":"Status to the steering group","scenario":"You present a monthly slide to a cross-functional steering committee. Last month your slide title was 'Project Atlas Update' and people spent five minutes guessing whether things were fine. The project is green but one milestone moved two weeks.","task":"Rewrite the slide headline so it carries the actual status, then write the one-sentence summary beneath it.","tips":["A headline should state the point, not the topic.","Green-with-one-caveat is still a verdict — say it.","The reader should know the answer before you talk."],"focus":["structure","clarity","audience"],"placeholder":"Atlas on track for launch; one milestone shifted two weeks, no launch-date impact."},
    {"id":"lead-mid-04","level":"mid","title":"Asking your director for headcount","scenario":"Your team is carrying a sustained 20% overload and you want approval to backfill an open role plus add one new hire. You've mentioned the workload in passing for a month but never made the ask directly.","task":"Write a short message (3-5 sentences) where the headcount ask is the first thing your director reads.","tips":["Put the specific request in sentence one: backfill plus one.","Quantify the overload so the ask is justified.","Make saying yes easy: scope, cost, and timing in one line."],"focus":["clarity","impact"],"placeholder":"I'm requesting approval to backfill the open analyst role and add one hire..."},
    {"id":"lead-mid-05","level":"mid","title":"Cross-functional unblock request","scenario":"Your team is blocked because the platform team hasn't provisioned a staging environment you requested two weeks ago. You're messaging the platform manager, a peer in another function, who has many competing requests.","task":"Write a message that leads with exactly what you need and by when, before the history.","tips":["First sentence: the specific ask and the date.","Don't open with how long you've been waiting.","Give just enough context to make it actionable, then stop."],"focus":["concision","clarity","audience"]},
    {"id":"lead-mid-06","level":"mid","title":"Delegating with the outcome first","scenario":"You're handing a senior report ownership of the vendor evaluation. You tend to explain the whole backstory before saying what you want them to do, leaving them unsure of the actual handoff.","task":"Write the delegation message so the ownership and the deliverable come first, context second.","tips":["Lead with: you now own X, and I need Y by Z.","Background is support — put it under the ask.","Be explicit about the decision rights you're handing over."],"focus":["clarity","structure"],"placeholder":"You're now the owner of the vendor evaluation; I need a recommendation by the 15th."},
    {"id":"lead-mid-07","level":"mid","title":"Escalating a real risk","scenario":"A key engineer on your team is leaving and the replacement won't ramp before a committed launch. You need your manager to either move the date or approve contractor support. You've been hoping it would resolve itself.","task":"Write a 3-5 sentence escalation that states the risk and the decision you need up front.","tips":["Name the risk and the decision in the first sentence.","Offer the two options, don't just describe the problem.","Say what you recommend so it's not just a worry dumped upward."],"focus":["clarity","impact","structure"]},
    {"id":"lead-mid-08","level":"mid","title":"The all-hands no one parses","scenario":"You're opening your team's monthly meeting. You usually start with a roundup of small updates and bury the one thing that matters — a reorg that changes who people report to next month.","task":"Write the first two sentences you'll say so the reorg lands immediately, ahead of the minor updates.","tips":["Lead with the change that affects them personally.","Small updates can wait — they're not the point.","Tell them what's changing for them before the rationale."],"focus":["audience","impact","structure"]},
    {"id":"lead-mid-09","level":"mid","title":"Recommendation, not a menu","scenario":"You're emailing your director with three options for next year's tooling budget. Last time you listed all three neutrally and got 'let's discuss' — a non-decision. You actually believe Option B is right.","task":"Rewrite the opening so your recommendation leads, with the options as support.","tips":["State your recommended option first, then the alternatives.","A neutral menu invites a stall; a recommendation invites a yes.","Give the one reason B wins before the full comparison."],"focus":["clarity","impact"],"placeholder":"I recommend Option B for next year's tooling. Two alternatives below for context."},
    {"id":"lead-mid-10","level":"mid","title":"Bad news to senior leadership","scenario":"A feature your team shipped caused a billing error affecting a few hundred customers. It's contained and refunds are issued. You need to brief your VP before they hear it elsewhere.","task":"Write a 3-5 sentence brief that leads with the situation and the fact that it's contained, not the technical cause.","tips":["First sentence: what happened and that it's under control.","Don't bury 'it's contained' under root-cause detail.","Lead with customer impact and the number affected."],"focus":["clarity","precision","impact"]},
    {"id":"lead-mid-11","level":"mid","title":"Peer manager alignment","scenario":"You and a peer manager in marketing disagree on launch sequencing. You're writing to propose your sequence and get alignment before it goes to your shared director. You tend to start with a long recap of the disagreement.","task":"Write the message so your proposed sequence is the first thing, with the rationale following.","tips":["Lead with the proposal, not the history of the debate.","Frame around the shared goal you both own.","Keep the recap to one line — they were there."],"focus":["concision","audience","clarity"]},
    {"id":"lead-mid-12","level":"mid","title":"The Friday deadline ask","scenario":"You need your manager to sign off on a contract renewal by Friday or you lose a vendor discount. Your draft opens with 'just circling back on the vendor thing' and never names the deadline clearly.","task":"Rewrite the opening so the decision needed and the deadline are unmissable in the first sentence.","tips":["Replace 'circling back' with the actual ask.","Put the deadline in sentence one, not the last line.","Say what happens if the date slips — the cost is the stake."],"focus":["clarity","precision","impact"],"placeholder":"I need your sign-off on the vendor renewal by Friday to keep the 15% discount."},
    {"id":"lead-mid-13","level":"mid","title":"Sprint review headline","scenario":"You're writing the end-of-sprint summary to your manager. The team completed most committed work but dropped one story to fix an urgent production issue. Your draft lists every ticket before the takeaway.","task":"Write the one-sentence takeaway that should sit at the top, then the supporting detail.","tips":["Lead with the net result, not the ticket list.","Explain the dropped story as a deliberate trade, up front.","Detail is skimmable support beneath the headline."],"focus":["structure","concision"],"placeholder":"We hit 9 of 10 committed stories; we swapped one to fix a P1 in production."},
    {"id":"lead-mid-14","level":"mid","title":"Performance concern to HR","scenario":"You're emailing your HR partner to start a documented improvement plan for a report. You need their guidance on the process. Your instinct is to narrate months of history before saying what you want from HR.","task":"Write the opening so your specific request to HR comes before the backstory.","tips":["First sentence: what you need from HR and by when.","The history is documentation — it supports, it doesn't lead.","Be precise about the process step you're asking them to enable."],"focus":["clarity","precision","audience"]},
    {"id":"lead-mid-15","level":"mid","title":"Reprioritization announcement","scenario":"Leadership shifted company priorities and your team must pause a project they've invested in for two quarters to pick up something new. You're announcing this to your team, who will be frustrated.","task":"Write the opening that states the change and what it means for their current work before explaining the why.","tips":["Lead with: we're pausing X to take on Y, effective now.","Tell them what happens to their in-flight work immediately.","Acknowledge the frustration, but after the clear headline."],"focus":["clarity","impact","audience"]},
    {"id":"lead-mid-16","level":"mid","title":"The quarterly business review slot","scenario":"You have five minutes in the QBR with senior leadership. Your team's headline is that you cut support ticket volume 30% by fixing the top defect. You're tempted to walk through the whole investigation first.","task":"Write the first two sentences of your verbal update so the 30% result leads.","tips":["State the win and the number first.","The investigation is support — five minutes won't fit it anyway.","Lead with the outcome leadership cares about, not the method."],"focus":["concision","impact","audience"],"placeholder":"We cut support tickets 30% this quarter by fixing the top defect."},
    {"id":"lead-mid-17","level":"mid","title":"Cross-team dependency warning","scenario":"Your team's roadmap depends on an API the data team plans to change. If they ship the change unannounced, three of your features break. You're writing to the data team's manager to flag this before their next release.","task":"Write a message that leads with the impact and what you need them to do, not the technical dependency chain.","tips":["First sentence: your features break unless X happens.","Lead with the consequence, then the mechanism.","State the specific action you need: notice, a flag, or a delay."],"focus":["clarity","precision","impact"]},
    {"id":"lead-mid-18","level":"mid","title":"Approving a team member's proposal upward","scenario":"A report pitched a process change you believe in. You're forwarding it to your director with your endorsement. Your draft summarizes the entire proposal before revealing that you support it and want approval.","task":"Write the opening so your endorsement and the ask for approval come first.","tips":["Lead with: I endorse this and recommend we approve it.","Don't make your director hunt for your position.","Summarize the proposal as support, after your stance."],"focus":["clarity","structure","impact"]},
    {"id":"lead-mid-19","level":"mid","title":"The meeting-or-not decision","scenario":"A peer manager keeps proposing a recurring sync you think is unnecessary. You've decided to decline and handle coordination async instead. Your draft opens with appreciation and reasons, burying the actual 'no.'","task":"Write the reply so your decision is clear in the first sentence, with the reasoning after.","tips":["Lead with the decision: let's not add the recurring meeting.","Reasons and the alternative follow the headline.","Be warm but unambiguous — don't leave them guessing."],"focus":["clarity","concision","audience"],"placeholder":"Let's skip the recurring sync and coordinate async instead — here's why."},
    {"id":"lead-mid-20","level":"mid","title":"Budget overrun heads-up","scenario":"Your team's project will exceed its budget by 12% because scope grew mid-quarter. You need to tell your director and get either more budget or a scope cut. Your instinct is to explain every scope change first.","task":"Write a 3-5 sentence message that leads with the overrun and the decision you need.","tips":["First sentence: we're tracking 12% over and need a decision.","Offer the two paths: more budget or cut scope.","Scope-change detail is support, not the opener."],"focus":["clarity","precision","impact"]},
    {"id":"lead-mid-21","level":"mid","title":"Onboarding a new report on priorities","scenario":"A new hire joins your team Monday and asks what matters most in their first month. You could narrate the team's whole history and roadmap, but they need to know the one thing to focus on first.","task":"Write the opening of your message so the single first-month priority leads, before the broader context.","tips":["Lead with the one outcome you want in month one.","Roadmap and history are background — keep them brief.","Make the first priority concrete and measurable."],"focus":["clarity","audience","concision"]},
    {"id":"lead-mid-22","level":"mid","title":"Saying no to a stakeholder request","scenario":"A senior stakeholder in another department asked your team to take on extra work that doesn't fit this quarter's commitments. You're declining for now but offering a future slot. Your draft opens with a long explanation of your team's load.","task":"Write the reply so the answer — not this quarter, but here's when — leads.","tips":["Lead with the decision and the alternative, together.","Don't make them read a workload essay to find the no.","Frame it around their goal so the no feels collaborative."],"focus":["clarity","audience","impact"],"placeholder":"We can't take this on this quarter, but I can slot it for Q4 — here's the tradeoff."},
    {"id":"lead-mid-23","level":"mid","title":"Incident postmortem summary","scenario":"Your team resolved a major outage. You're sending the postmortem to your VP and peer managers. The doc is thorough, but your email intro buries the one thing leadership wants: what you changed so it won't recur.","task":"Write the email intro so the prevention measure and current status lead, before linking the full doc.","tips":["First sentence: resolved, and here's the change that prevents recurrence.","Lead with what leadership will act on, not the timeline.","Link the detailed doc as optional depth."],"focus":["clarity","impact","audience"]},
    {"id":"lead-mid-24","level":"mid","title":"Asking a peer to reprioritize","scenario":"You need a peer manager's team to move your request up their queue because a customer commitment depends on it. You tend to start by validating how busy they are before getting to the ask.","task":"Write the message so the specific reprioritization ask and the customer stake come first.","tips":["Lead with the ask and why it's urgent for a customer.","Empathy for their load can come after the headline.","Be specific: which item, moved ahead of what, by when."],"focus":["clarity","precision","impact"]},
    {"id":"lead-mid-25","level":"mid","title":"The weekly leadership digest","scenario":"You send a weekly written digest to your manager covering your team. It currently reads as a chronological log, and your manager has said they 'can't find the signal.' This week the signal is that a key risk cleared and you're now fully on track.","task":"Write the top line of the digest so the week's single most important point leads, before the activity log.","tips":["Open with the one thing that changed your status this week.","A chronological log buries the signal — promote it.","Everything else becomes a skimmable list beneath the headline."],"focus":["structure","concision","clarity"],"placeholder":"Top line: the vendor risk cleared, so we're now fully on track for launch."}
  ],
  "start-with-the-audience": [
    {"id":"audience-mid-01","level":"mid","title":"Translate your team's quarter up","scenario":"Your team spent the quarter refactoring a brittle billing service so it stops failing at month-end. Your VP doesn't care about the refactor; she cares about whether finance can close the books on time and whether you'll need more headcount.","task":"Write a 3-4 sentence quarter summary for your VP that leads with what she cares about, not the engineering work.","tips":["Open with the outcome she's accountable for, not the activity.","Translate 'refactor' into a consequence: fewer month-end failures.","Name the headcount question explicitly so she isn't guessing."],"focus":["audience","impact"],"placeholder":"Month-end billing is now reliable, which means…"},
    {"id":"audience-mid-02","level":"mid","title":"Same news, two readers","scenario":"A key project is two weeks behind. You have to tell both your boss and your own team. Your boss needs to manage expectations upward; your team needs to know what changes for them tomorrow.","task":"Write two short versions of the same delay update — one for your boss, one for your reports — each leading with that reader's stake.","tips":["Boss version: revised date, cause in one line, what you're doing about it.","Team version: what to stop, start, or reprioritize this week.","Don't paste the same paragraph twice — the stake is different."],"focus":["audience","clarity"]},
    {"id":"audience-mid-03","level":"mid","title":"Pitch across to a peer manager","scenario":"You need the marketing manager's team to give you two weeks of design time next sprint. You're tempted to explain why your roadmap matters. She cares about her own deliverables and what she gets back.","task":"Write a 3-5 sentence ask to your peer that frames the trade around her interests, not yours.","tips":["Lead with what's in it for her team, or the shared goal.","Be specific about scope and timing so she can say yes fast.","Offer something back — sequencing, credit, or reciprocal help."],"focus":["audience","concision"]},
    {"id":"audience-mid-04","level":"mid","title":"Explain the tradeoff to a non-technical stakeholder","scenario":"The head of sales wants a feature shipped in three weeks. Doing it safely takes six; doing it in three means cutting tests and risking outages during demos. He has no technical context.","task":"Explain the three-week-vs-six-week tradeoff to the head of sales in plain terms so he can choose, without jargon.","tips":["Frame it as his decision with his risk: demos breaking.","Translate 'cutting tests' into 'higher chance of a visible failure.'","Give him a clear recommendation, not just options."],"focus":["audience","clarity"]},
    {"id":"audience-mid-05","level":"mid","title":"Right altitude for the exec","scenario":"Your director asked 'how's the platform migration going?' in a hallway. You start to describe the database cutover sequence and see her eyes glaze. She wanted the headline and the one risk that matters.","task":"Write the 2-3 sentence answer you should have given — headline status, one number, one risk.","tips":["More senior and time-pressed means higher and shorter.","Lead with on-track / at-risk, then the single number that proves it.","Name one risk, not five."],"focus":["audience","concision"]},
    {"id":"audience-mid-06","level":"mid","title":"What does your reader already know?","scenario":"You're writing an update to a peer manager in finance about a data issue. You almost open with the table schema and the ETL job name — context she's never seen. She knows the business numbers, not your pipeline.","task":"Write the opening two sentences of the update, starting from what she already knows and bridging to the new fact.","tips":["Name what she shares first, then add the missing piece.","Skip system names that mean nothing to her.","Anchor on a business number she recognizes."],"focus":["audience","clarity"]},
    {"id":"audience-mid-07","level":"mid","title":"Promote a report's work upward","scenario":"One of your engineers quietly prevented a major outage by catching a config error before release. You want leadership to see it. They don't track config errors; they track customer trust and uptime.","task":"Write a 2-3 sentence note to your leadership chain that frames your report's catch in terms leadership values.","tips":["Translate 'caught a config error' into 'avoided an outage during peak.'","Quantify the avoided impact if you can.","Make the person visible by name and contribution."],"focus":["audience","impact"]},
    {"id":"audience-mid-08","level":"mid","title":"One message, one primary audience","scenario":"Your launch email will be read by your team, two peer managers, and your VP. You keep adding caveats for each group and it's becoming a wall no one will read.","task":"Rewrite the email's opening so it speaks to one primary decision-maker, and let the rest read over their shoulder.","tips":["Pick the one reader whose decision matters most.","Write for them; move side-notes for others to the bottom.","One audience, one register — don't flatten to please everyone."],"focus":["audience","structure"]},
    {"id":"audience-mid-09","level":"mid","title":"Reframe a tech win for the CFO's office","scenario":"Your team cut cloud spend by moving workloads to cheaper instances. You want to renew the project. The finance partner cares about run-rate savings and predictability, not instance types.","task":"Write a 3-4 sentence renewal pitch aimed at the finance partner's stake.","tips":["Lead with annualized savings and predictability.","Drop instance-type detail; keep the number.","Tie continued funding to continued savings."],"focus":["audience","impact"]},
    {"id":"audience-mid-10","level":"mid","title":"Tailor feedback for your report","scenario":"A senior engineer on your team writes brilliant code but loses non-technical partners in meetings. You need her to see the gap. She values precision and evidence, not vague 'be clearer' advice.","task":"Write the 3-4 sentence feedback framed for how she takes in information — concrete, evidenced, respectful of her skill.","tips":["Lead with a specific moment, not a label.","Speak to her stake: her ideas getting adopted.","Give one concrete behavior to change."],"focus":["audience","clarity"]},
    {"id":"audience-mid-11","level":"mid","title":"Brief your boss before she briefs hers","scenario":"Your VP is about to present your team's results to the exec staff. She needs a tight set of talking points she can defend, not your full status doc. She'll be challenged on cost and timeline.","task":"Write 3 talking points your VP can use upward — each a claim plus the one fact that backs it.","tips":["Anticipate the exec's questions: cost, timeline, risk.","Each point: a defensible claim with a single supporting number.","Keep it to what she can say in 30 seconds each."],"focus":["audience","structure"]},
    {"id":"audience-mid-12","level":"mid","title":"Across to legal, not down to your team","scenario":"You need legal to approve a new data-retention setting. You'd normally explain the implementation. Legal cares about compliance risk and what data is kept, for how long, and who can access it.","task":"Write a 3-4 sentence note to legal that leads with their questions, not your build.","tips":["Frame around risk, retention period, and access — their lens.","State plainly what data is and isn't affected.","Ask the specific approval you need so they can act."],"focus":["audience","precision"]},
    {"id":"audience-mid-13","level":"mid","title":"Cut the curse of knowledge from your draft","scenario":"You wrote an all-hands update for your department. Re-reading it, half the sentences assume readers know your team's internal tool names, acronyms, and the history of a project they've never touched.","task":"Rewrite one jargon-heavy sentence from such an update into one a reader outside your team would understand.","tips":["Replace internal names with what they do.","Assume zero shared history; build the bridge.","Keep it honest — translate, don't dumb down."],"focus":["audience","clarity"],"placeholder":"Original: 'We migrated Atlas to the new Falcon shards and deprecated the legacy sync.'"},
    {"id":"audience-mid-14","level":"mid","title":"Lead with the peer's stake in a conflict","scenario":"Your team and a peer's team both want the same shared QA resource next month. You want to make your case without it sounding like a turf grab. The peer manager cares about her own launch date.","task":"Write the opening 2-3 sentences of your message that acknowledge her stake before making your case.","tips":["Name her launch risk first — show you see it.","Propose a shared answer, not a winner-take-all.","Save your own case until after you've shown you get hers."],"focus":["audience","impact"]},
    {"id":"audience-mid-15","level":"mid","title":"Altitude for a skip-level","scenario":"Your VP's boss — a skip-level you rarely talk to — asks for a one-paragraph readout on your team's biggest initiative. You have ten pages of detail. He has two minutes and wants the bet and the risk.","task":"Write the one-paragraph readout: the bet, the single proof point, the main risk.","tips":["One governing message up top.","One number that proves traction.","One risk, stated plainly — don't bury it."],"focus":["audience","concision"]},
    {"id":"audience-mid-16","level":"mid","title":"Sell the roadmap to your own reports","scenario":"Leadership reprioritized your team onto a less exciting reliability project. Your reports wanted to build the new feature. You need them bought in, and they care about impact and their own growth, not the org chart.","task":"Write a 3-5 sentence message to your team that frames the reliability work around what they care about.","tips":["Connect the work to user impact and their own credibility.","Be honest about the tradeoff; don't oversell.","Name the growth or visibility in it for them."],"focus":["audience","impact"]},
    {"id":"audience-mid-17","level":"mid","title":"Translate a metric for a non-data exec","scenario":"You want to flag that p95 latency rose from 200ms to 600ms. Your director doesn't know what p95 means but does know customers complain when the app feels slow.","task":"Write a 2-3 sentence flag to your director that conveys the severity without requiring her to know the metric.","tips":["Translate the metric into felt experience: app feels sluggish.","Convey magnitude in human terms, not just the number.","Say what you need from her, if anything."],"focus":["audience","clarity"]},
    {"id":"audience-mid-18","level":"mid","title":"Calibrate for a mixed-seniority room","scenario":"You're prepping a 5-minute readout for a meeting with two ICs from your team and your VP in the room. You can either go deep for the ICs or high for the VP, but not both at once.","task":"Write the opening you'd lead with, choosing the VP as primary audience, and note where the IC detail goes instead.","tips":["Pick the primary decision-maker and write to her.","Open high; signal that detail is available on request.","Park IC-level depth for follow-up, not the main line."],"focus":["audience","structure"]},
    {"id":"audience-mid-19","level":"mid","title":"Frame a budget ask for your director","scenario":"You want to hire a contractor to clear a backlog. You're excited about finally fixing tech debt. Your director approves spend based on outcome, payback, and risk of not doing it.","task":"Write a 3-4 sentence budget ask framed entirely around your director's decision criteria.","tips":["Lead with the outcome and rough payback, not the debt.","Name the cost of doing nothing.","Make the ask specific: scope, duration, dollars."],"focus":["audience","impact"]},
    {"id":"audience-mid-20","level":"mid","title":"Write for the reader who'll forward it","scenario":"You send your peer manager a status note. You know he'll forward it straight to his own VP without rewriting it. So your note has to survive a reader you'll never meet.","task":"Rewrite your note's first two sentences so they stand on their own for a senior reader who lacks your context.","tips":["Assume the forwarded reader has no backstory.","Front-load the headline and why it matters.","Strip in-jokes and internal shorthand."],"focus":["audience","clarity"]},
    {"id":"audience-mid-21","level":"mid","title":"Same recommendation, three stakes","scenario":"You're recommending the team adopt a new incident-management tool. The CFO, your engineers, and the support manager each care about completely different things — cost, pager pain, and customer response time.","task":"Write one sentence pitching the same tool to each of the three readers, each reframed around that reader's stake.","tips":["CFO: cost and risk avoided.","Engineers: the daily pain it removes.","Support manager: faster customer response."],"focus":["audience","concision"]},
    {"id":"audience-mid-22","level":"mid","title":"Bridge two functions that talk past each other","scenario":"Your engineers say 'the API contract changed'; the partnered product manager hears nothing actionable. You need to broker a shared understanding so both sides act. Each speaks its own dialect.","task":"Write a 2-3 sentence reframe of 'the API contract changed' that the product manager can act on.","tips":["Translate the change into product consequence: what breaks for users or partners.","Name the decision the PM now has to make.","Drop the engineering term or define it in passing."],"focus":["audience","clarity"]},
    {"id":"audience-mid-23","level":"mid","title":"Decide what to leave out for the board-bound deck","scenario":"Your VP asks for slides she'll fold into a leadership review. You have a detailed analysis. Most of it is noise at her altitude — she needs the conclusion and the one chart that earns it.","task":"Write the single headline sentence for the slide plus a note on the one chart you'd keep and what you'd cut.","tips":["Headline is the takeaway, not the topic.","Keep the one visual that proves it; cut the rest.","Higher altitude means less, not more."],"focus":["audience","concision"]},
    {"id":"audience-mid-24","level":"mid","title":"Reframe a 'no' for the requester's stake","scenario":"A peer manager asked your team to take on extra work and you have to decline. He cares about getting his goal met, not about your capacity spreadsheet. A flat 'we're full' damages the relationship.","task":"Write a 3-4 sentence decline that leads with his goal and offers a path, not just a refusal.","tips":["Acknowledge his goal first — show you get the stake.","Be honest about the constraint without drowning him in detail.","Offer an alternative or a timeline so it's a 'not now,' not a wall."],"focus":["audience","impact"]},
    {"id":"audience-mid-25","level":"mid","title":"Turn a status doc into a decision request","scenario":"You wrote a thorough status update for your director, but it reads like a diary of activity. What she actually needs is to decide whether to pull a second team in. Buried in paragraph four is the real ask.","task":"Rewrite the opening so it leads with the decision you need from her, framed around her stake in the deadline.","tips":["Lead with the decision, not the chronology.","Frame it around the date she's accountable for.","Give her the recommendation plus the one fact she needs to choose."],"focus":["audience","structure"]}
  ],
  "structure-that-carries": [
    {"id":"structure-mid-01","level":"mid","title":"SCQA your headcount ask","scenario":"Your team has absorbed a 30% jump in support volume since the last product launch, and two engineers are now context-switching across four queues. You want to ask leadership to approve one new hire in the upcoming planning cycle.","task":"Write a 4-6 sentence SCQA framing that lands on the headcount recommendation.","tips":["Situation: the staffing level everyone already accepts.","Complication: name the volume jump and its concrete cost.","Question: what the complication forces leadership to decide.","Answer: one new hire, stated in a single line."],"focus":["structure","impact"]},
    {"id":"structure-mid-02","level":"mid","title":"Lead with the recommendation","scenario":"You're sending a decision doc to your director about whether to rebuild or patch a fragile internal tool your team owns. You've written three pages of analysis but buried the recommendation on page two.","task":"Write the opening two sentences that state your recommendation first, then signal the support to follow.","tips":["Put the answer in sentence one — rebuild or patch.","Promise the structure: name how many reasons back it.","Don't make the reader hunt for your point."],"focus":["structure","clarity"]},
    {"id":"structure-mid-03","level":"mid","title":"Group the messy team update","scenario":"Your weekly update to your manager has become a flat list of eleven items: a hire started, a deploy slipped, a customer escalated, a teammate is on leave, two bugs shipped, a vendor renewed, and more. It reads as noise.","task":"Rewrite the update as one governing line plus 2-3 grouped buckets.","tips":["Find categories: people, delivery, risks often work.","Lead with the one sentence that names the real story of the week.","Group the eleven items so they're memorable, don't list them all."],"focus":["structure","concision"]},
    {"id":"structure-mid-04","level":"mid","title":"Pyramid for the quarterly readout","scenario":"You're preparing a quarterly readout for your VP. Last quarter your team hit its delivery target, missed on quality metrics, and made progress on a long-standing tech-debt initiative.","task":"Write the top of the pyramid: one governing message plus the three buckets beneath it.","tips":["Start with a single sentence that sums the quarter.","Three buckets, no more — the reader can hold three.","Each bucket should be a claim, not a topic label."],"focus":["structure","clarity"]},
    {"id":"structure-mid-05","level":"mid","title":"Frame the process change","scenario":"Your cross-functional team still plans annually, but priorities have shifted three times in the last six months and your roadmap is already stale. You want to propose moving to quarterly planning.","task":"Write a 4-6 sentence SCQA framing that earns agreement before you reveal the recommendation.","tips":["Situation: state the annual cadence as the shared norm.","Complication: the three shifts that broke it.","Question: how should we plan in a market that moves this fast?","Answer: quarterly planning, in one line."],"focus":["structure","audience"]},
    {"id":"structure-mid-06","level":"mid","title":"PREP the planning answer","scenario":"In a leadership review, your director asks point-blank: 'Why should we give your team more runway on the migration?' You tend to ramble when put on the spot.","task":"Answer in four moves using Point, Reason, Example, Point.","tips":["Point: the migration needs one more sprint.","Reason: why that's true, in one clause.","Example: one concrete piece of evidence.","Point: restate the ask with conviction."],"focus":["structure","impact"]},
    {"id":"structure-mid-07","level":"mid","title":"Top line for the proposal","scenario":"You're pitching leadership on standing up a small platform team drawn from your group. Your draft opens with background on how the current setup evolved over two years.","task":"Rewrite the opening so the governing recommendation comes first, before any background.","tips":["Answer-first: name the platform team in sentence one.","Background is support, not the headline — move it down.","Tell the reader why now in one clause."],"focus":["structure","concision"]},
    {"id":"structure-mid-08","level":"mid","title":"Group the cross-functional asks","scenario":"Your project plan needs help from three other teams, and you've listed nine separate requests across design, data, and legal. The sponsor's eyes glaze over.","task":"Restructure the nine requests into grouped asks under one governing statement.","tips":["Group by the team you're asking, or by the milestone they unblock.","Lead with what the project needs to ship on time.","Make each group a single, decision-ready ask."],"focus":["structure","clarity"]},
    {"id":"structure-mid-09","level":"mid","title":"SCQA for a tooling investment","scenario":"Your team builds on a legacy CI pipeline that everyone has tolerated for years. It now fails twice a week and is eating a full day of engineering time per sprint. You want budget for a replacement.","task":"Write a 4-6 sentence SCQA framing ending in the recommendation to fund the replacement.","tips":["Situation: the pipeline everyone has lived with.","Complication: quantify the failures and lost time.","Question: keep absorbing the cost, or invest?","Answer: fund the replacement, one line."],"focus":["structure","precision"]},
    {"id":"structure-mid-10","level":"mid","title":"Recommendation before rationale","scenario":"You're writing a decision doc on whether to sunset a low-usage feature your team maintains. You laid out usage data, support cost, and migration risk first, and saved the call for the end.","task":"Write the doc's first three sentences: the decision, then a one-line preview of the three reasons.","tips":["State the call to sunset up front.","Preview the three supporting reasons by name.","Save the data tables for the body, not the opener."],"focus":["structure","clarity"]},
    {"id":"structure-mid-11","level":"mid","title":"Pyramid the incident review","scenario":"You're presenting last month's outage to leadership. You have a tangle of contributing factors: a missed alert, an under-tested deploy, an on-call gap, and a slow rollback.","task":"Write the governing message plus 2-3 grouped causes for the top of your readout.","tips":["One sentence on what actually happened and its impact.","Group causes: detection, prevention, response often work.","Lead with the story, not the timeline of events."],"focus":["structure","concision"]},
    {"id":"structure-mid-12","level":"mid","title":"Frame the reorg proposal","scenario":"Your team of eight has grown organically and now spans two distinct product areas, causing constant priority collisions. You want to propose splitting it into two pods.","task":"Write a 4-6 sentence SCQA framing that lands on the two-pod recommendation.","tips":["Situation: the single-team setup as it stands.","Complication: the priority collisions, made concrete.","Question: how do we let both areas move?","Answer: split into two pods, one line."],"focus":["structure","audience"]},
    {"id":"structure-mid-13","level":"mid","title":"PREP on the spot","scenario":"In a planning meeting a peer manager challenges your priority: 'Why is the analytics rebuild ahead of the customer-requested integrations?' You need a crisp, confident answer.","task":"Respond using Point, Reason, Example, Point in four tight moves.","tips":["Point: the rebuild has to come first.","Reason: it unblocks the integrations downstream.","Example: one concrete dependency that's already biting.","Point: restate, calmly."],"focus":["structure","impact"]},
    {"id":"structure-mid-14","level":"mid","title":"One idea, three buckets","scenario":"You're writing the executive summary of a project proposal. Your draft has seven parallel bullet points that all feel equally important and none of which stick.","task":"Collapse the seven points into one governing claim supported by exactly three buckets.","tips":["Find the single idea all seven serve.","Cluster the seven into three groups of related points.","Working memory holds about three chunks — respect that."],"focus":["structure","concision"]},
    {"id":"structure-mid-15","level":"mid","title":"Decision doc opener","scenario":"You must choose a vendor for your team's new monitoring stack between two finalists. Your doc currently opens with a feature-by-feature comparison matrix.","task":"Write an answer-first opening: name the vendor you recommend, then preview the deciding factors.","tips":["Recommendation in sentence one — name the vendor.","Preview the two or three factors that decided it.","The matrix is evidence; it belongs below the call."],"focus":["structure","clarity"]},
    {"id":"structure-mid-16","level":"mid","title":"SCQA for the deadline slip","scenario":"A committed feature will miss its date because a dependency from another team arrived three weeks late. You need to tell your director and propose a new plan without it sounding like excuses.","task":"Write a 4-6 sentence SCQA framing that ends with your proposed recovery plan.","tips":["Situation: the commitment everyone agreed to.","Complication: the late dependency, stated as fact not blame.","Question: how do we recover from here?","Answer: your recovery plan, one line."],"focus":["structure","precision"]},
    {"id":"structure-mid-17","level":"mid","title":"Group the quarterly wins","scenario":"For your team's quarterly review, you've assembled a flat list of fourteen accomplishments. Leadership won't remember fourteen things.","task":"Rewrite as one headline claim about the quarter plus three grouped categories of wins.","tips":["Lead with the one thing the quarter proved.","Cluster fourteen wins into three themes.","Pick the strongest example to carry each theme."],"focus":["structure","impact"]},
    {"id":"structure-mid-18","level":"mid","title":"Pyramid the roadmap ask","scenario":"You're asking leadership to approve next half's roadmap for your team. Your draft walks chronologically through every initiative with no clear hierarchy.","task":"Write the governing message plus the three strategic buckets your initiatives ladder up to.","tips":["Start with the one outcome the roadmap delivers.","Three strategic buckets, each a claim about value.","Map initiatives under buckets, don't march through them in order."],"focus":["structure","clarity"]},
    {"id":"structure-mid-19","level":"mid","title":"Frame the budget defense","scenario":"Finance has flagged your team's cloud spend as a target for cuts, but that spend backs a workload that drives real revenue. You want to reframe the conversation before the cut lands.","task":"Write a 4-6 sentence SCQA framing that reframes the spend and proposes the right next step.","tips":["Situation: the spend as it appears on the ledger.","Complication: what the line item actually buys.","Question: cut blindly, or right-size with data?","Answer: your proposed next step, one line."],"focus":["structure","audience"]},
    {"id":"structure-mid-20","level":"mid","title":"PREP the tradeoff","scenario":"Your skip-level asks why your team chose to pay down tech debt this quarter instead of shipping a visible new feature. You want to defend the call without sounding defensive.","task":"Answer in Point, Reason, Example, Point.","tips":["Point: paying the debt was the right call.","Reason: it was slowing every feature we ship.","Example: one feature it had already delayed.","Point: restate the call with conviction."],"focus":["structure","impact"]},
    {"id":"structure-mid-21","level":"mid","title":"Top-line the status email","scenario":"Your project status email to stakeholders opens with two paragraphs of context before anyone learns whether the project is on track.","task":"Rewrite the opening line to deliver the bottom line first: on track, at risk, or off track, with the one reason why.","tips":["State the status in the first six words.","Give the single biggest reason in the same breath.","Detail follows the verdict, never precedes it."],"focus":["structure","concision"]},
    {"id":"structure-mid-22","level":"mid","title":"Group the risk register","scenario":"You're briefing your director on a project's risks and have eight loose items: a key dependency, a flaky test suite, a contractor offboarding, an ambiguous spec, and more. It reads as a worry-list.","task":"Restructure the eight risks into one governing statement plus 2-3 grouped risk categories.","tips":["Group by type: people, technical, external.","Lead with the overall risk posture in one sentence.","Name the one risk in each group that needs a decision now."],"focus":["structure","clarity"]},
    {"id":"structure-mid-23","level":"mid","title":"SCQA for adopting a standard","scenario":"Your three sub-teams each use a different code-review process, and onboarding engineers across them is slow and inconsistent. You want to propose one shared standard.","task":"Write a 4-6 sentence SCQA framing that lands on adopting the single standard.","tips":["Situation: each team's own way of working.","Complication: the onboarding friction it now causes.","Question: keep diverging, or align?","Answer: one shared standard, one line."],"focus":["structure","precision"]},
    {"id":"structure-mid-24","level":"mid","title":"Pyramid the hiring case","scenario":"You're making the case to your VP for two new roles on your team. Your draft mixes anecdotes, metrics, and roadmap pressure into one undifferentiated wall of text.","task":"Write the governing claim plus three grouped reasons the two roles are justified.","tips":["One sentence: we need these two roles to do X.","Three buckets: demand, capacity gap, opportunity cost.","Put your sharpest number under each bucket."],"focus":["structure","impact"]},
    {"id":"structure-mid-25","level":"mid","title":"Frame the scope cut","scenario":"A flagship project is over capacity and you've concluded the team should cut two of its five planned features to protect the date. You need to bring leadership along, not just announce it.","task":"Write a 4-6 sentence SCQA framing that ends with the recommendation to cut scope.","tips":["Situation: the five-feature commitment as agreed.","Complication: the capacity reality, in concrete terms.","Question: slip the date, or trim the scope?","Answer: cut these two features, one line."],"focus":["structure","audience"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-mid-01","level":"mid","title":"Trim the all-hands announcement","scenario":"You're rolling out a new ticketing tool to your 14-person support team. Your draft announcement runs four paragraphs of preamble before it ever says what's changing or when.","task":"Rewrite the announcement so the first sentence states the change and the date, then cut the rest to a third of its length.","tips":["Lead with what's changing and when.","Delete throat-clearing like 'I wanted to take a moment'.","Move any 'why' to a single short line after the headline."],"focus":["concision","structure","clarity"],"placeholder":"Hi team, I wanted to take a moment to reach out and let you all know about something that's been in the works for a while now regarding the way we handle incoming tickets..."},
    {"id":"concise-mid-02","level":"mid","title":"De-hedge the recommendation to your boss","scenario":"You're recommending that your team pause a low-value workstream. Your message to your director is buried under qualifiers: 'I could be wrong, but maybe we might want to possibly consider...'","task":"Rewrite it as one plain recommendation your director can approve or reject.","tips":["Make one clear claim, then the reason.","Keep the respect, drop the hedging.","If you have a real uncertainty, name it specifically."],"focus":["impact","concision"]},
    {"id":"concise-mid-03","level":"mid","title":"Halve the leadership update","scenario":"Your monthly written update to the senior leadership team has ballooned to a full page of dense prose. Most readers skim the first two lines.","task":"Cut the update to under 120 words while keeping every real decision and number.","tips":["Ask of each sentence: does a leader need this to act?","Turn status narration into short bullets.","Cut adjectives that carry no information."],"focus":["concision","audience","structure"]},
    {"id":"concise-mid-04","level":"mid","title":"Kill the nominalizations","scenario":"Your team's process doc reads: 'The implementation of the new escalation procedure resulted in a reduction in the duration of resolution for high-priority incidents.'","task":"Rewrite the sentence using strong verbs instead of noun-phrases.","tips":["Hunt for words ending in -tion, -ment, -ance.","Ask whether a verb does the work in half the space.","Aim to roughly halve the word count."],"focus":["concision","precision","clarity"]},
    {"id":"concise-mid-05","level":"mid","title":"Cut the runway from the email","scenario":"You email a peer manager to ask for two of her engineers next sprint. Your message spends three sentences explaining that you're about to ask before you ask.","task":"Rewrite so the request appears in the first sentence.","tips":["Delete 'I wanted to reach out to let you know that'.","Start at the point: the ask and the timeframe.","Keep context to one line, after the request."],"focus":["concision","impact"],"placeholder":"Hi Priya, I hope you're doing well. I wanted to reach out because I've been thinking about our upcoming sprint and the work that's coming down the pipe, and I was wondering whether..."},
    {"id":"concise-mid-06","level":"mid","title":"Tighten the project status to one line","scenario":"A stakeholder asks 'where are we?' on a migration your team owns. Your instinct is to recount the whole history of the project.","task":"Answer the status in a single sentence: where it stands and the one thing that matters next.","tips":["State the headline status first.","Name the next milestone and date.","Resist recounting history they didn't ask for."],"focus":["concision","clarity","audience"]},
    {"id":"concise-mid-07","level":"mid","title":"Trim the meeting recap","scenario":"After your weekly team sync you send a recap that reruns the entire conversation. People stopped reading it weeks ago.","task":"Reduce the recap to decisions made and owners for each action item — nothing else.","tips":["Cut discussion narration; keep outcomes.","Format as decision + owner + date.","If a line has no owner or decision, delete it."],"focus":["concision","structure"]},
    {"id":"concise-mid-08","level":"mid","title":"Compress the policy reminder","scenario":"You need to remind your team about the new expense-approval threshold. Your draft restates the entire policy from scratch in six sentences.","task":"Rewrite as a two-sentence reminder that gives only what changed and what to do.","tips":["Lead with the new number or rule.","Drop restating policy people already know.","One sentence of action, one of context max."],"focus":["concision","precision","clarity"]},
    {"id":"concise-mid-09","level":"mid","title":"Cut the meta-commentary","scenario":"Your update to your VP is full of phrases that announce you're about to speak: 'It's worth noting that...', 'I should mention that...', 'As you may be aware...'","task":"Delete every meta-commentary phrase and rewrite the points directly.","tips":["Delete the runway and start at the substance.","'As you may be aware' usually means 'cut this'.","Read it aloud; flag any sentence that's about the sentence."],"focus":["concision","impact"]},
    {"id":"concise-mid-10","level":"mid","title":"Shrink the reorg announcement","scenario":"You're announcing that two of your sub-teams are merging. Your draft hedges so much that nobody can tell whether the merge is final.","task":"Rewrite so the first sentence states the decision plainly, then give the date and one reason.","tips":["State it as a decision, not a possibility.","Hedging here reads as anxiety; cut it.","Headline, date, reason — in that order."],"focus":["clarity","impact","concision"]},
    {"id":"concise-mid-11","level":"mid","title":"One-line the ask in a long thread","scenario":"A 30-message email thread among your reports has stalled. You jump in to break the tie, but your draft summarizes all 30 messages first.","task":"Write a reply that states your decision in the first line and the rationale in one more.","tips":["Lead with the call, not the recap.","Two sentences: decision, then why.","Trust people to remember their own thread."],"focus":["concision","impact","clarity"]},
    {"id":"concise-mid-12","level":"mid","title":"Trim the praise so it lands","scenario":"You're recognizing a report's strong quarter in a team channel, but the message is so padded with qualifiers and generic phrasing that the specific win disappears.","task":"Rewrite to name the specific accomplishment in one or two crisp sentences.","tips":["Cut generic praise words; keep the concrete result.","One specific win beats three vague compliments.","Short praise reads as more sincere, not less."],"focus":["concision","precision","impact"]},
    {"id":"concise-mid-13","level":"mid","title":"Halve the risk callout","scenario":"You're flagging a delivery risk to your program lead, but your message wanders through every contributing factor before stating the risk itself.","task":"Rewrite so the risk and your proposed mitigation each get one sentence, up front.","tips":["State the risk plainly before the causes.","Pair it immediately with what you're doing about it.","Cut the tour of contributing factors."],"focus":["concision","structure","clarity"]},
    {"id":"concise-mid-14","level":"mid","title":"Cut filler from the goal statement","scenario":"Your quarterly team goal currently reads: 'Our overarching aim is to basically work towards trying to improve the general overall quality of our customer interactions in a meaningful way.'","task":"Rewrite the goal as one specific, concise sentence.","tips":["Delete 'basically', 'general', 'overall', 'in a meaningful way'.","Swap vague aims for something checkable.","Strong verb, concrete object, done."],"focus":["concision","precision","clarity"]},
    {"id":"concise-mid-15","level":"mid","title":"Compress the onboarding note","scenario":"You welcome a new hire to your team with a warm but sprawling message that buries the three things they actually need on day one.","task":"Keep the warmth in one line, then list only the three day-one essentials.","tips":["One sentence of welcome, then specifics.","Bullet the essentials so they don't get lost.","Cut everything that can wait until week two."],"focus":["concision","structure","audience"]},
    {"id":"concise-mid-16","level":"mid","title":"Tighten the 'no' to a request","scenario":"A peer asks your team to take on extra scope. You're declining, but your draft softens the no through five sentences of cushioning until it reads like a maybe.","task":"Rewrite to decline clearly and kindly in two sentences.","tips":["A clear no respects their planning.","Cushion once, not five times.","Offer one alternative if you have it — briefly."],"focus":["clarity","concision","impact"]},
    {"id":"concise-mid-17","level":"mid","title":"Strip the bloated proposal intro","scenario":"Your one-page proposal to fund a tooling upgrade opens with a paragraph of background no decision-maker needs before the ask.","task":"Replace the intro with a single sentence stating what you want funded and the expected payoff.","tips":["Open with the ask and the payoff.","Background, if needed, goes lower and shorter.","Decision-makers read the first line first."],"focus":["structure","concision","impact"]},
    {"id":"concise-mid-18","level":"mid","title":"De-duplicate the team memo","scenario":"Your change memo makes the same point three times in slightly different words across three paragraphs, hoping repetition adds weight.","task":"Collapse the redundancy into one clear statement of the point.","tips":["Find the sentences that say the same thing.","Keep the sharpest version; delete the rest.","Repetition reads as padding, not emphasis."],"focus":["concision","clarity"]},
    {"id":"concise-mid-19","level":"mid","title":"Cut hedging from the performance note","scenario":"You're giving a report written feedback that they're missing deadlines. Your draft hedges so heavily ('it sort of seems like maybe sometimes') that the message is unreadable.","task":"Rewrite to state the pattern plainly and respectfully, in two sentences.","tips":["Name the specific pattern, not a vague impression.","Drop 'sort of', 'maybe', 'sometimes' if the pattern is real.","Plain feedback is kinder than fog."],"focus":["clarity","precision","impact"]},
    {"id":"concise-mid-20","level":"mid","title":"Shrink the cross-team update","scenario":"You send a weekly update to three partner teams. It runs long because you explain context each of them already has.","task":"Rewrite to under 80 words by cutting context the audience already knows.","tips":["Assume the reader's working memory.","Keep only what changed since last week.","Cut any sentence that re-explains the obvious."],"focus":["concision","audience"]},
    {"id":"concise-mid-21","level":"mid","title":"One sentence per agenda item","scenario":"Your team meeting agenda has grown into paragraphs of description under each item, and people stop reading past item two.","task":"Rewrite each agenda item as a single sentence naming the topic and the decision needed.","tips":["Topic plus desired outcome, one line each.","Cut descriptions that belong in the meeting itself.","If an item needs no decision, question why it's there."],"focus":["concision","structure","clarity"]},
    {"id":"concise-mid-22","level":"mid","title":"Trim the escalation to your boss","scenario":"You're escalating a blocker to your manager. Your draft spends four sentences apologizing for escalating before naming the blocker or what you need.","task":"Rewrite so the blocker and the specific help you need come first, in two sentences.","tips":["Lead with the blocker and the ask.","Cut the apology for escalating; it's your job.","Be specific about what unblocks you."],"focus":["concision","impact","clarity"]},
    {"id":"concise-mid-23","level":"mid","title":"Compress the deadline change","scenario":"You're telling your team a deliverable slipped by a week. Your message wanders through every reason before stating the new date.","task":"Rewrite so the new date is in the first sentence, with one line of reason and one of next steps.","tips":["New date first; reasons are secondary.","One sentence of cause, not a forensic report.","End with the single next action."],"focus":["clarity","concision","structure"]},
    {"id":"concise-mid-24","level":"mid","title":"Cut the qualifier pile-up","scenario":"Your recommendation reads: 'I think it's probably fairly likely that this could potentially be somewhat helpful in most cases.' It carries almost no information.","task":"Rewrite as a single confident claim, naming any real uncertainty specifically.","tips":["Stacked qualifiers cancel each other out.","Pick one level of confidence and commit.","If genuinely unsure, name what would resolve it."],"focus":["concision","precision","impact"]},
    {"id":"concise-mid-25","level":"mid","title":"Halve the rambling FAQ answer","scenario":"In your team's internal FAQ, the answer to 'Who approves overtime?' runs a full paragraph of caveats before naming the approver.","task":"Rewrite the answer to lead with the approver in the first sentence, keeping only essential caveats.","tips":["Answer the literal question first.","Caveats come after the answer, trimmed hard.","If a caveat is rare, cut or footnote it."],"focus":["concision","clarity","audience"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-mid-01","level":"mid","title":"Back the headcount ask","scenario":"Your team of six is at capacity and you want a seventh engineer. In a planning meeting your director asks why you can't absorb the work. You're tempted to say the team is 'slammed' and 'drowning.'","task":"Make the case for one more hire in 3-4 sentences using concrete load metrics a skeptic would accept.","tips":["Quantify the gap: hours, tickets, or velocity vs. demand.","Tie the number to a cost or risk of not hiring.","Avoid 'overwhelmed', 'crazy busy' — show the math."],"focus":["precision","impact"],"placeholder":"We're carrying..."},
    {"id":"precision-mid-02","level":"mid","title":"The skeptic's 'based on what?'","scenario":"You tell your VP your team's quality has 'gotten much better this quarter.' She immediately replies, 'Based on what?'","task":"Give a single-sentence answer that attaches the evidence to the claim before she has to ask again.","tips":["Lead with the metric, then the baseline and timeframe.","Pick the one number that best proves quality.","Don't hedge with 'I think' or 'kind of.'"],"focus":["precision","clarity"]},
    {"id":"precision-mid-03","level":"mid","title":"One insight from the dashboard","scenario":"Your weekly team dashboard shows: throughput 47 tickets (+9%), cycle time 3.1 days (-0.4), escaped bugs 5 (flat), on-call pages 22 (-30%), CSAT 4.3 (+0.1). Your manager asks for 'the story' in standup.","task":"Answer in 2-3 sentences: the one insight, not all five numbers.","tips":["Choose the metric that tells the story.","State the insight, then the number that supports it.","Note honestly what stayed flat."],"focus":["clarity","concision"]},
    {"id":"precision-mid-04","level":"mid","title":"Budget ask with a number","scenario":"You want $40k for a new tooling license that would speed up your team. Your finance partner is skeptical of 'productivity' claims and has heard them all before.","task":"Write a 2-3 sentence justification that turns the productivity claim into a checkable number with a payback.","tips":["Convert time saved into hours or dollars.","Anchor to current pain, not a hypothetical.","Name the payback period explicitly."],"focus":["precision","impact"]},
    {"id":"precision-mid-05","level":"mid","title":"Vague status in the leadership update","scenario":"Your draft monthly update reads: 'The migration is progressing nicely and should wrap up soon. The team has been working hard and morale is good.'","task":"Rewrite it with concrete progress, a date, and one specific signal of team health.","tips":["Replace 'soon' with a date or a percent complete.","Swap 'morale is good' for an observable signal.","Cut the effort language — show results, not hours."],"focus":["precision","clarity"]},
    {"id":"precision-mid-06","level":"mid","title":"Defend the prioritization call","scenario":"You deprioritized a feature your skip-level wanted in favor of paying down tech debt. He asks why in a 1:1 and isn't happy. You start with 'it just felt like the right call.'","task":"State the decision rationale in 3 sentences with the evidence that made debt the higher priority.","tips":["Name the cost the debt is currently imposing (a number).","Compare it against the feature's expected reach.","Own the call — 'I decided', not 'we kind of felt.'"],"focus":["structure","precision"]},
    {"id":"precision-mid-07","level":"mid","title":"Quantify your team's impact","scenario":"At your performance review, your director asks what your team delivered this half. You want to say you 'shipped a lot and the team really stepped up.'","task":"Write 3-4 sentences that quantify your team's impact in outcomes, not activity.","tips":["Lead with an outcome (revenue, time saved, risk removed), not a feature list.","Attach one number to each claim.","Avoid 'a lot', 'tons', 'huge' — use figures."],"focus":["impact","precision"]},
    {"id":"precision-mid-08","level":"mid","title":"What → So what → Now what","scenario":"You found that 70% of your team's interruptions come from one upstream team's unclear handoffs. You want to raise it with your peer manager.","task":"Make the case in 3 sentences using What → So What → Now What, ending in a specific ask.","tips":["What: the fact and its number.","So what: the cost to your team's delivery.","Now what: the one concrete change you're requesting."],"focus":["structure","clarity"]},
    {"id":"precision-mid-09","level":"mid","title":"Trim the metric list","scenario":"Your slide for the leadership review has eight team KPIs in a table. Your manager warns you the audience will tune out and asks you to lead with the point.","task":"Write the one-sentence headline that should sit above the table, naming the single most important movement.","tips":["Pick the metric that drives a decision.","State the direction and magnitude in the headline.","Let the table be support, not the message."],"focus":["concision","impact"]},
    {"id":"precision-mid-10","level":"mid","title":"Evidence for the deadline slip","scenario":"Your project will land two weeks late. You need to tell your director without sounding like excuses. Your instinct is 'there were a lot of unexpected things.'","task":"Explain the slip in 3 sentences with a specific cause and a concrete recovery date.","tips":["Name the one biggest driver, with a number if you can.","Give a firm new date, not 'soon.'","Separate the fact from the apology."],"focus":["precision","clarity"]},
    {"id":"precision-mid-11","level":"mid","title":"Promotion case for a report","scenario":"You're advocating to promote a direct report. The calibration committee is tough and wants evidence, not adjectives. Your draft says she's 'a strong performer who's grown a lot.'","task":"Write 3-4 sentences making the case with specific, checkable accomplishments at the next level.","tips":["Cite scope and outcomes, not effort or attitude.","Quantify at least two impacts.","Show next-level behavior with a concrete example."],"focus":["precision","impact"]},
    {"id":"precision-mid-12","level":"mid","title":"Replace the intensifiers","scenario":"A draft from one of your leads, going up to your VP, reads: 'Adoption has significantly increased, performance is much improved, and the team responded very quickly to the incident.'","task":"Rewrite the sentence replacing each intensifier with a number, date, or concrete fact (invent plausible specifics).","tips":["Every 'significantly/much/very' should become a figure.","Add a baseline so the change is legible.","Keep it to one tight sentence per claim."],"focus":["precision","concision"]},
    {"id":"precision-mid-13","level":"mid","title":"Justify the reorg of your team","scenario":"You want to split your 9-person team into two pods. Your director asks what problem this solves. You're tempted to say it 'feels too big and communication is hard.'","task":"State the rationale in 3 sentences with a concrete symptom and the metric you expect to move.","tips":["Quantify the current coordination cost.","Name the specific outcome the split improves.","Avoid 'feels' — point to an observable signal."],"focus":["structure","precision"]},
    {"id":"precision-mid-14","level":"mid","title":"Defend the estimate","scenario":"You quoted six weeks for a project. A senior leader pushes: 'That seems high — why so long?' You don't want to cave or wave your hands.","task":"Justify the estimate in 2-3 sentences by breaking it into concrete components a skeptic can check.","tips":["Decompose the number into 2-3 chunks.","Anchor to a comparable past project if you can.","Hold the line with evidence, not insistence."],"focus":["precision","structure"]},
    {"id":"precision-mid-15","level":"mid","title":"The 'how do you know?' on attrition","scenario":"You tell your director you're worried about burnout on your team. She asks how you know it isn't just one person venting.","task":"Answer in 2-3 sentences with specific signals across the team, not one anecdote.","tips":["Cite a measurable pattern (PTO, overtime, survey, turnover).","Show it's broad, not a single voice.","Lead with the strongest signal."],"focus":["precision","audience"]},
    {"id":"precision-mid-16","level":"mid","title":"Insight over the QBR data dump","scenario":"For your quarterly business review, you've pasted every team metric into the deck. Your manager says senior leaders will ask 'so what?' within 30 seconds.","task":"Write the 2-3 sentence opener that delivers one insight and the decision it implies.","tips":["Name the headline movement and why it matters here.","Drop the metrics that don't change a decision.","End on the action you want leadership to take."],"focus":["impact","concision"]},
    {"id":"precision-mid-17","level":"mid","title":"Specifics in the kickoff brief","scenario":"Your project kickoff one-pager says the goal is to 'meaningfully improve the onboarding experience and reduce drop-off.' Your director asks what success looks like.","task":"Rewrite the goal as a measurable target with a baseline and a date.","tips":["Turn 'reduce drop-off' into a number and timeframe.","State the current baseline so progress is legible.","Make it something you could later prove or disprove."],"focus":["precision","clarity"]},
    {"id":"precision-mid-18","level":"mid","title":"Trade-off backed by numbers","scenario":"You can fund either faster CI or a second QA hire, not both. Your director wants your recommendation with reasoning, not a both-sides shrug.","task":"Recommend one in 3 sentences, with the concrete numbers that make it the better bet.","tips":["Quantify the upside of each, then pick.","Lead with the recommendation, then the evidence.","Acknowledge the cost of the option you dropped."],"focus":["impact","precision"]},
    {"id":"precision-mid-19","level":"mid","title":"From 'users complained' to evidence","scenario":"You're escalating a product problem your team is fielding. Your draft to the PM lead says 'users are really unhappy and we're getting slammed with complaints.'","task":"Rewrite it with a volume, a trend, and the concrete impact on your team.","tips":["Quantify the complaint volume and its trend.","Tie it to a cost (time, churn, on-call load).","Replace 'slammed' with a measured figure."],"focus":["precision","impact"]},
    {"id":"precision-mid-20","level":"mid","title":"Survive the budget challenge","scenario":"In a budget review, a skeptical senior leader says your team's contractor spend 'looks like a lot for what it delivered.' You have 30 seconds to respond.","task":"Defend or concede in 2-3 sentences, anchored to specific outputs per dollar.","tips":["Map the spend to concrete deliverables.","Use a ratio (cost per X) the leader can judge.","If the data is weak, say so precisely rather than bluffing."],"focus":["precision","audience"]},
    {"id":"precision-mid-21","level":"mid","title":"Make the win checkable","scenario":"Your team reduced incident volume and you want to highlight it in the all-hands shout-out your manager is compiling. Your line reads: 'Big improvement in reliability this quarter.'","task":"Rewrite the shout-out so the win is specific and verifiable in one sentence.","tips":["Give the before and after numbers.","Add the timeframe and what drove it.","Make a skeptic able to confirm it."],"focus":["precision","concision"]},
    {"id":"precision-mid-22","level":"mid","title":"Tie the ask to the metric","scenario":"You want approval to spend a sprint on developer-experience work. Your director only funds things tied to outcomes. You start with 'the team really wants this and it'll help morale.'","task":"Reframe the ask in 3 sentences around a measurable outcome the investment moves.","tips":["Replace 'morale' with a metric (cycle time, ramp time, retention).","Quantify the current pain.","Name what you'll measure to prove it worked."],"focus":["impact","precision"]},
    {"id":"precision-mid-23","level":"mid","title":"Precise risk in the status report","scenario":"Your status report says the launch has 'some risk' around capacity. Your director hates vague risk language and wants to know how worried to be.","task":"Rewrite the risk line with a concrete likelihood, trigger, and mitigation.","tips":["Quantify or bound the risk (e.g., 'fails above X load').","Name the specific trigger to watch.","State the mitigation and its cost."],"focus":["precision","clarity"]},
    {"id":"precision-mid-24","level":"mid","title":"Capacity math for the new project","scenario":"Leadership wants your team to take on a new initiative on top of current work. You need to show what gives. Saying 'we're already pretty full' won't land.","task":"In 3 sentences, show your team's capacity in concrete terms and what you'd trade to take this on.","tips":["Express capacity as a number (people, sprint points, hours).","Name what specifically gets dropped or delayed.","Make the trade-off explicit, not implied."],"focus":["precision","structure"]},
    {"id":"precision-mid-25","level":"mid","title":"One number that reframes the debate","scenario":"Your peers are arguing in a planning meeting about whether to invest in a flaky test suite. The debate is all opinion. You pulled the actual data this morning.","task":"Drop in one sharp, specific data point (invent a plausible one) and the decision it points to, in 2 sentences.","tips":["Lead with the single most decision-relevant number.","Connect it straight to the choice on the table.","Resist listing more than one figure."],"focus":["impact","concision"]}
  ],
  "executive-presence": [
    {"id":"presence-mid-01","level":"mid","title":"Own the rollout call","scenario":"Your team is split on launching a new onboarding flow now or holding it two weeks for polish. Your director asks for your read in tomorrow's leadership sync. You're tempted to hand both options up the chain.","task":"Write a 3-4 sentence recommendation that takes a clear position and stays open to challenge.","tips":["Lead with your recommendation, not the trade-offs.","Give the single strongest reason.","Invite pushback without softening the call."],"focus":["impact","clarity"]},
    {"id":"presence-mid-02","level":"mid","title":"Fact, judgment, next step","scenario":"Your team's ticket backlog grew for the second sprint running. You believe it's an understaffed QA rotation, not scope creep, but you haven't proven it. Your VP wants an explanation.","task":"Write 3-4 sentences that separate what you know, what you believe, and what you'd do to confirm.","tips":["State the fact plainly, no hedging.","Label your judgment as a judgment with its reasoning.","End with one concrete test."],"focus":["precision","structure"]},
    {"id":"presence-mid-03","level":"mid","title":"Make the call for your team","scenario":"Two of your reports disagree on which vendor to standardize on and have escalated it to you. They both want you to decide. Further debate is just stalling delivery.","task":"Write a short message (3-4 sentences) that makes the decision, names the deciding reason, and closes the debate respectfully.","tips":["Decide in the first sentence.","Give the reason that tipped it.","Acknowledge the losing option's merit without reopening it."],"focus":["clarity","impact"]},
    {"id":"presence-mid-04","level":"mid","title":"Recommend, don't present","scenario":"You've been asked to summarize three hiring strategies for the leadership team. Your draft lists all three neutrally, pushing the choice back up to them.","task":"Rewrite the close so it leads with your recommendation and the reason behind it.","tips":["Name the option you recommend first.","Pair it with one justifying reason.","Leave a door open for challenge."],"focus":["impact","structure"],"placeholder":"Of the three approaches, I recommend..."},
    {"id":"presence-mid-05","level":"mid","title":"Signpost a tangled update","scenario":"Your monthly status to leadership keeps reading as a stream of consciousness. There are really two issues this month: a slipped deadline and a budget overrun. Right now they blur together.","task":"Write a 3-4 sentence update that signposts the two issues so a reader can follow your logic.","tips":["Tell the reader how many issues there are up front.","Use 'first' and 'second' to separate them.","Keep each issue to one tight sentence."],"focus":["structure","clarity"]},
    {"id":"presence-mid-06","level":"mid","title":"Take a position with a peer","scenario":"A peer manager wants to share a contractor between your two teams; you think it will dilute focus and slow both of you down. You've been hedging to keep the peace.","task":"Write 2-3 sentences to your peer that state your position clearly while keeping the relationship intact.","tips":["State your position without apologizing for it.","Give the concrete reason, not a vague worry.","Offer a path forward, not just a no."],"focus":["clarity","audience"]},
    {"id":"presence-mid-07","level":"mid","title":"Confidence in the leadership review","scenario":"In your quarterly business review, leadership asks whether your team will hit next quarter's target. You know the answer is a qualified yes with one real risk, but you're inclined to over-explain.","task":"Write a 2-3 sentence answer that gives a direct read first, then the one risk.","tips":["Answer yes/no/qualified in the first sentence.","Name only the one risk that matters.","Don't bury the answer in context."],"focus":["concision","impact"]},
    {"id":"presence-mid-08","level":"mid","title":"Own a missed number","scenario":"Your team missed its delivery date by a week. Leadership wants to know what happened. You feel the pull to list every dependency that went wrong.","task":"Write 2-3 sentences that own the miss, name the real cause, and state the recovery commitment.","tips":["Own it plainly before explaining.","Name the single root cause.","End with the new committed date."],"focus":["precision","impact"]},
    {"id":"presence-mid-09","level":"mid","title":"Recommend a headcount choice","scenario":"You have budget for one new hire and must choose between a senior engineer and two juniors. Your skip-level asked for your recommendation, not a menu.","task":"Write a 3-4 sentence recommendation that picks one and defends it with a single reason.","tips":["Pick before you justify.","Tie the reason to a team outcome.","Acknowledge the trade-off you're accepting."],"focus":["clarity","impact"]},
    {"id":"presence-mid-10","level":"mid","title":"Hold the line on scope","scenario":"A senior stakeholder keeps adding features to your team's release. You've decided to hold scope to protect the date, and you need to tell them without sounding obstructive.","task":"Write 2-3 sentences that hold the line decisively while staying collaborative.","tips":["State the decision, not just the constraint.","Frame it as protecting a shared outcome.","Offer when the new ask can land instead."],"focus":["clarity","audience"]},
    {"id":"presence-mid-11","level":"mid","title":"Separate signal from noise","scenario":"Your team's NPS dropped four points. You suspect it's one churned enterprise account skewing a small sample, not a real trend, but you're not sure. Your director wants your interpretation.","task":"Write 3-4 sentences separating the fact, your judgment, and the next step to confirm.","tips":["State the number as a fact, no spin.","Flag your interpretation as a hypothesis.","Name how you'd validate it."],"focus":["precision","structure"]},
    {"id":"presence-mid-12","level":"mid","title":"Decisive in a cross-functional standoff","scenario":"In a cross-functional planning meeting, design and engineering are deadlocked on a tradeoff and both look to you. You have a view but keep softening it to avoid friction.","task":"Write 2-3 sentences that state your position and break the deadlock.","tips":["Lead with where you land.","Give the deciding criterion.","Invite a counter-case without retreating."],"focus":["impact","clarity"]},
    {"id":"presence-mid-13","level":"mid","title":"Brief up with a clear ask","scenario":"You need leadership to approve a one-week slip to fix a quality issue. Your draft email wanders through context before the ask, and the ask is buried.","task":"Rewrite the opening so the recommendation and the ask come first.","tips":["Put the ask in sentence one.","Follow with the one reason it's the right call.","Save background for after the ask."],"focus":["structure","concision"],"placeholder":"I recommend we slip the release one week. Here's why:"},
    {"id":"presence-mid-14","level":"mid","title":"Defend a decision under questioning","scenario":"You decided to cut a feature from the release to protect quality. In review, a senior leader challenges it hard. You feel the urge to justify every detail.","task":"Write a 2-3 sentence response that acknowledges the valid concern and defends the call with specifics.","tips":["Acknowledge the legitimate part first.","Answer with a specific, not a generality.","Stay calm and own the decision."],"focus":["precision","impact"]},
    {"id":"presence-mid-15","level":"mid","title":"Say 'I don't know' with a path","scenario":"In a leadership Q&A, you're asked for your team's exact cost-per-acquisition this quarter and you don't have it memorized. You're tempted to throw out a rough guess.","task":"Write a 2-3 sentence answer that admits the gap and attaches a path to the answer.","tips":["Say plainly you don't have it.","Commit to a time you'll deliver it.","Flag any rough estimate as not-yet-confirmed."],"focus":["clarity","impact"]},
    {"id":"presence-mid-16","level":"mid","title":"Set direction for your team","scenario":"Your team is drifting between two priorities and looking to you for a call. You've been describing both as important, which has left everyone half-committed to each.","task":"Write 2-3 sentences to your team that name the one priority and the reason, decisively.","tips":["Name the single priority first.","Give the reason it wins right now.","Tell them what the other can wait for."],"focus":["clarity","impact"]},
    {"id":"presence-mid-17","level":"mid","title":"Recommend killing a project","scenario":"A project your team has invested three months in isn't working. You believe it should be stopped. You need to recommend that to leadership without sounding like you're admitting failure.","task":"Write 3-4 sentences recommending you stop, with the evidence and the reframe.","tips":["State the recommendation to stop clearly.","Back it with the fact that decided it.","Frame the learning, not the failure."],"focus":["impact","precision"]},
    {"id":"presence-mid-18","level":"mid","title":"Cut the qualifiers","scenario":"Your recommendation memo is riddled with 'I think maybe', 'sort of', and 'it might be possible that'. The content is sound but it reads as uncertain.","task":"Rewrite a hedged recommendation sentence into one that projects calibrated confidence.","tips":["Strip the reflexive qualifiers.","Keep honest uncertainty only where it's real.","State the position as a position."],"focus":["concision","impact"],"placeholder":"I think we should maybe sort of consider possibly moving the deadline..."},
    {"id":"presence-mid-19","level":"mid","title":"Take a clear stance in writing","scenario":"A peer manager emails asking whether you support reorganizing the shared on-call rotation. You have a clear view: no, not yet. Your draft reply tiptoes around it.","task":"Write a 2-3 sentence reply that states your stance plainly and gives the reason.","tips":["Answer the actual question in sentence one.","Give the one reason that drives your stance.","Offer the condition that would change your mind."],"focus":["clarity","audience"]},
    {"id":"presence-mid-20","level":"mid","title":"Frame a recommendation for leadership","scenario":"You're recommending leadership invest in tooling that will slow your team for a quarter but pay off after. The benefit is real but the short-term cost is what they'll fixate on.","task":"Write 3-4 sentences that lead with the recommendation and pre-empt the cost objection.","tips":["State the recommendation first.","Name the short-term cost before they do.","Make the payoff concrete and time-bound."],"focus":["structure","audience"]},
    {"id":"presence-mid-21","level":"mid","title":"Decisive when the data is mixed","scenario":"Two metrics point opposite ways on whether to extend a pilot. Leadership wants a recommendation, not a both-sides summary. You have to commit despite the ambiguity.","task":"Write 3-4 sentences that make a recommendation, name which signal you weighted more, and why.","tips":["Commit to a recommendation despite the mix.","Say which signal you trusted more and why.","Name what would make you reverse."],"focus":["impact","precision"]},
    {"id":"presence-mid-22","level":"mid","title":"Own your team's mistake upward","scenario":"A report on your team shipped a bug that reached a customer. Leadership is asking who's accountable. You're the manager and the answer is you, not your report by name.","task":"Write 2-3 sentences that own it as the manager and state the fix, without throwing your report under the bus.","tips":["Take accountability as the manager.","Don't name or blame the individual.","State the concrete corrective step."],"focus":["audience","impact"]},
    {"id":"presence-mid-23","level":"mid","title":"Land the headline first","scenario":"Your update to leadership opens with five minutes of background before the one thing they need: the launch is on track but one integration is at risk. The headline is buried at the end.","task":"Rewrite the opening so the headline lands in the first sentence.","tips":["Put the bottom line first.","Lead with status, then the single risk.","Make context follow the headline, not precede it."],"focus":["structure","concision"],"placeholder":"Bottom line: launch is on track, with one risk —"},
    {"id":"presence-mid-24","level":"mid","title":"Push back on a peer's plan","scenario":"A peer manager proposes a shared roadmap that quietly deprioritizes your team's biggest commitment. You need to push back clearly in the planning thread without it becoming a turf war.","task":"Write 2-3 sentences that state your disagreement and the concrete reason, then propose a way forward.","tips":["State the disagreement directly.","Anchor it to a commitment, not a preference.","Propose a constructive next step."],"focus":["clarity","audience"]},
    {"id":"presence-mid-25","level":"mid","title":"Project calm certainty in a crisis","scenario":"A production incident hit your team's service and leadership is anxious in the incident channel. You know the status, the cause, and the ETA. Your messages so far have been scattered.","task":"Write a 3-4 sentence update that projects calm command: status, cause, ETA, next checkpoint.","tips":["Lead with current status in plain terms.","State the known cause without speculation.","Give an ETA and when you'll update next."],"focus":["structure","impact"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-mid-01","level":"mid","title":"The skip-level's pointed question","scenario":"In a quarterly review, your skip-level VP cuts in: \"Why is your team's velocity down two sprints in a row?\" You know the cause: you pulled two engineers onto an urgent incident, and onboarding a new hire ate time.","task":"Write a 2-4 sentence answer that names the real cause first, then what it means going forward.","tips":["Lead with the direct cause, not a defense.","Own the tradeoff you made on purpose.","Close with when velocity recovers."],"focus":["clarity","impact"]},
    {"id":"pressure-mid-02","level":"mid","title":"Missed the quarterly target","scenario":"Your team came in 12% under its quarterly delivery target. In a leadership readout, the COO asks: \"What happened, and is next quarter at risk too?\"","task":"Write a direct answer that states the miss, the one root cause, and your read on next quarter.","tips":["Don't bury the miss under context.","One root cause, not a list of excuses.","Give a clear yes/no/at-risk on next quarter."],"focus":["precision","impact"]},
    {"id":"pressure-mid-03","level":"mid","title":"A report asks why they didn't get promoted","scenario":"A strong performer on your team asks point-blank: \"I hit every goal this cycle. Why wasn't I promoted?\" The honest answer is the scope wasn't yet at the next level, and you didn't advocate hard enough.","task":"Write a 3-4 sentence reply that answers honestly without dodging or over-cushioning.","tips":["Answer the 'why' directly in the first sentence.","Name what's missing in concrete terms, not vague 'impact'.","Own your part if you fell short."],"focus":["clarity","audience"]},
    {"id":"pressure-mid-04","level":"mid","title":"Peer manager challenges your roadmap","scenario":"In a cross-functional planning meeting, a peer manager pushes back: \"Your roadmap assumes my team delivers the API by March, and we never agreed to that.\" She's partly right — you assumed a date that was never confirmed.","task":"Write a composed reply that concedes the valid point and re-anchors on a path forward.","tips":["Acknowledge the part she's right about, plainly.","Don't get defensive about the assumption.","Pivot to the concrete decision you both need."],"focus":["audience","impact"]},
    {"id":"pressure-mid-05","level":"mid","title":"\"Do you actually believe this plan?\"","scenario":"Your director stops the meeting and asks directly: \"Forget the slides — do you actually think your team can ship this by the deadline?\" You have real doubts about one workstream but confidence in the rest.","task":"Write a 2-4 sentence honest answer that distinguishes what you're confident in from what you're not.","tips":["Don't give blanket optimism you don't feel.","Separate the solid part from the risky part.","Attach a specific risk and what would de-risk it."],"focus":["precision","impact"]},
    {"id":"pressure-mid-06","level":"mid","title":"Don't know the number live","scenario":"In a leadership sync, a senior leader asks for your team's exact attrition rate this year. You don't have it memorized and refuse to guess wrong.","task":"Write a short reply that admits the gap and attaches a path to the answer.","tips":["Don't bluff a figure.","Say when you'll send the exact number.","If you offer a rough sense, flag it as unconfirmed."],"focus":["precision","impact"]},
    {"id":"pressure-mid-07","level":"mid","title":"Report questions a decision you made","scenario":"You reassigned a key project to another engineer. The report who lost it asks in your 1:1: \"Why did you take that away from me?\" The real reason: you needed your most senior person on the riskiest piece.","task":"Write a 3-4 sentence answer that gives the real reason without making it personal.","tips":["Answer the 'why' directly, no euphemism.","Frame it as a staffing call, not a verdict on them.","Name what you do want from them next."],"focus":["clarity","audience"]},
    {"id":"pressure-mid-08","level":"mid","title":"Defending a hire that isn't working out","scenario":"In a calibration meeting, another manager says: \"Your new hire isn't pulling their weight — was that the right call?\" You still believe in the hire but they're ramping slowly.","task":"Write a composed 2-4 sentence reply that holds your position with specifics, not defensiveness.","tips":["Acknowledge the slow ramp honestly.","Cite the concrete signal that keeps your confidence.","State the checkpoint where you'll reassess."],"focus":["precision","impact"]},
    {"id":"pressure-mid-09","level":"mid","title":"Put on the spot to commit a date","scenario":"Mid-meeting, your VP asks: \"So can you commit to launching in six weeks — yes or no?\" You can commit to most of it, but one dependency is outside your control.","task":"Write a direct answer that gives a real commitment and names the one condition on it.","tips":["Don't hedge the whole thing to cover one risk.","Commit to what you control, clearly.","Name the single dependency that could move it."],"focus":["clarity","precision"]},
    {"id":"pressure-mid-10","level":"mid","title":"\"Why should I trust your estimate this time?\"","scenario":"Your last estimate slipped by three weeks. Now leadership asks: \"Why is this new estimate any more reliable?\" The honest answer: you've added buffer and removed the dependency that broke last time.","task":"Write a 3-4 sentence reply that owns the past miss and gives concrete reasons this one is firmer.","tips":["Concede the last slip without groveling.","Name what specifically changed in how you estimated.","Avoid promising perfection — promise the safeguard."],"focus":["structure","impact"]},
    {"id":"pressure-mid-11","level":"mid","title":"Report asks about layoff rumors","scenario":"A nervous report asks in your 1:1: \"Are layoffs coming to our team?\" You genuinely don't know the full picture and can't promise anything.","task":"Write a short, honest reply that neither lies nor fuels panic.","tips":["Don't make a promise you can't keep.","Say plainly what you do and don't know.","Tell them what you'll do when you learn more."],"focus":["audience","clarity"]},
    {"id":"pressure-mid-12","level":"mid","title":"Senior leader calls your priorities wrong","scenario":"A senior leader says flatly: \"I think your team is working on the wrong things.\" You disagree on the top priority but he has a point about a second one.","task":"Write a composed 3-4 sentence reply that defends your top priority and concedes the second.","tips":["Don't cave on the priority you believe in.","Give the one reason it's number one.","Genuinely grant the point he's right about."],"focus":["precision","impact"]},
    {"id":"pressure-mid-13","level":"mid","title":"Cross-functional blame in the room","scenario":"After a botched launch, a peer manager says in front of leadership: \"This failed because your team shipped late.\" Reality: your team was late, but their incomplete spec was the bigger cause.","task":"Write a 2-4 sentence reply that owns your part without absorbing blame that isn't yours.","tips":["Take the slice that's genuinely yours, first.","State the bigger cause factually, not as a counterattack.","Point to the fix, not the fault."],"focus":["precision","impact"]},
    {"id":"pressure-mid-14","level":"mid","title":"\"What's your team even doing all day?\"","scenario":"A frustrated stakeholder, in a status meeting, snaps: \"From outside it looks like nothing's shipping — what is your team actually doing?\" The team is heads-down on invisible platform work.","task":"Write a composed answer that makes the invisible work concrete without sounding defensive.","tips":["Stay even — don't match the heat.","Translate hidden work into one visible outcome.","Give the date the work becomes visible."],"focus":["clarity","audience"]},
    {"id":"pressure-mid-15","level":"mid","title":"Report challenges your feedback as unfair","scenario":"In a review conversation, your report pushes back: \"That rating isn't fair — I did everything you asked.\" You believe the rating is right, but you owe them the specific gap.","task":"Write a 3-4 sentence reply that holds the rating and names the concrete gap.","tips":["Don't retreat to soften the moment.","Cite a specific example, not a general impression.","Separate effort from the outcome you needed."],"focus":["precision","audience"]},
    {"id":"pressure-mid-16","level":"mid","title":"Asked to justify head-count","scenario":"In budget planning, the CFO's deputy asks: \"Why do you need two more engineers when output is flat?\" You believe output is flat because the team is over capacity on maintenance.","task":"Write a 2-4 sentence answer that links the ask to a concrete constraint, not a wish.","tips":["Answer the 'why two' with a specific bottleneck.","Tie the hire to an outcome, not comfort.","Avoid vague 'we're busy' language."],"focus":["precision","structure"]},
    {"id":"pressure-mid-17","level":"mid","title":"\"Did you know this was failing?\"","scenario":"A project quietly went off the rails and leadership just found out. The director asks: \"Did you know it was in trouble, and if so why didn't you flag it?\" You did sense it but waited too long to escalate.","task":"Write an honest 3-4 sentence answer that owns the late escalation cleanly.","tips":["Answer the direct question yes or no, first.","Own the delay without elaborate excuses.","State what you've changed so it won't recur."],"focus":["clarity","impact"]},
    {"id":"pressure-mid-18","level":"mid","title":"Curveball metric you weren't expecting","scenario":"You're presenting a roadmap when a leader interrupts: \"What's your team's on-call burnout look like right now?\" It's off-topic and you don't have a hard figure.","task":"Write a short reply that handles the curveball without faking precision.","tips":["Don't manufacture a number to look prepared.","Give the honest qualitative read you do have.","Offer to follow up with the real data."],"focus":["precision","impact"]},
    {"id":"pressure-mid-19","level":"mid","title":"Defending an unpopular call to your team","scenario":"You decided the team adopts a new process leadership mandated. In a team meeting a report asks: \"Do you even agree with this, or are you just passing it down?\" You have reservations but will commit.","task":"Write a 3-4 sentence answer that's honest about your view yet leads the team forward.","tips":["Don't pretend it was your idea if it wasn't.","Be honest about your reservation, briefly.","Land on genuine commitment, not grudging compliance."],"focus":["audience","impact"]},
    {"id":"pressure-mid-20","level":"mid","title":"\"Whose fault is the outage?\"","scenario":"After an outage, your skip-level asks directly in the postmortem: \"Was this a process failure or a people failure?\" The honest answer is process — a missing check — not any individual.","task":"Write a 2-4 sentence answer that points to the real cause without scapegoating a report.","tips":["Name the system gap plainly.","Protect your people — don't name-and-blame.","End with the specific fix going in."],"focus":["precision","impact"]},
    {"id":"pressure-mid-21","level":"mid","title":"Asked if you'd make the same call again","scenario":"A decision you made backfired. Leadership asks: \"Knowing what you know now, would you make that call again?\" Honestly, you'd make it differently but the original logic was sound at the time.","task":"Write a composed 3-4 sentence answer that's honest about the hindsight without disowning your judgment.","tips":["Separate 'right with what I knew' from 'wrong outcome'.","Name the one thing you'd do differently.","Don't grovel and don't get defensive."],"focus":["precision","impact"]},
    {"id":"pressure-mid-22","level":"mid","title":"Report asks for a raise you can't promise","scenario":"In a 1:1, a top performer asks directly: \"Can you get me a 15% raise this cycle?\" You can advocate but can't guarantee it, and the real ceiling is lower.","task":"Write an honest 3-4 sentence reply that doesn't over-promise yet respects them.","tips":["Don't dangle a number you can't deliver.","Be straight about what you can and can't control.","Commit to a concrete action and a timeline."],"focus":["clarity","audience"]},
    {"id":"pressure-mid-23","level":"mid","title":"Grilled on a number that looks bad","scenario":"Your team's bug-escape rate spiked this month. In review, a leader asks: \"Why did quality fall off a cliff?\" The spike is real but driven mostly by one risky migration, not a broad decline.","task":"Write a 2-4 sentence answer that gives the honest read and the precise driver.","tips":["Don't dismiss the number, but don't catastrophize it.","Isolate the one driver behind the spike.","State what contains it going forward."],"focus":["precision","clarity"]},
    {"id":"pressure-mid-24","level":"mid","title":"Put on the spot to back another team","scenario":"In a leadership meeting your VP turns to you: \"Do you support the platform team's reorg proposal — yes or no?\" You support the intent but have one serious concern.","task":"Write a 2-4 sentence answer that gives a clear position and names your one concern.","tips":["Lead with where you actually stand.","Don't hide the concern to seem agreeable.","Make the concern specific and actionable."],"focus":["clarity","precision"]},
    {"id":"pressure-mid-25","level":"mid","title":"\"Why is morale on your team low?\"","scenario":"An engagement survey flagged your team low on morale. Your director asks directly: \"What's going on with your people?\" You know the main cause is months of crunch on a deprioritized project.","task":"Write an honest 3-4 sentence answer that names the cause and what you're doing about it.","tips":["Don't deflect to 'it's an industry thing'.","Name the concrete cause you can point to.","End with a specific action, not a sentiment."],"focus":["clarity","impact"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-mid-01","level":"mid","title":"Pitch the headcount ask","scenario":"Your team of six is underwater; two key projects are slipping because you're stretched. You need to convince your VP to approve one additional hire in the next planning cycle.","task":"Write a 4-6 sentence pitch that frames the before/after of adding the role and puts a concrete cost on the status quo.","tips":["Paint 'where we are' with a real symptom, not a feeling.","Quantify what the gap is costing in deals, delays, or burnout.","Name the 'can't we just reprioritize?' objection and answer it."],"focus":["impact","structure"],"placeholder":"Right now my team is carrying..."},
    {"id":"narrative-mid-02","level":"mid","title":"Align a peer manager","scenario":"A change you want requires a peer manager's team to adopt a shared intake process. They're protective of their current workflow and see your ask as extra work for them.","task":"Write a 3-5 sentence case that frames the change as a win for their team too, not just yours.","tips":["Lead with what they get, not what you need.","Make the shared cost of the current chaos concrete.","Pre-empt 'this is more work for us' with the time it saves them."],"focus":["audience","impact"]},
    {"id":"narrative-mid-03","level":"mid","title":"Sell the roadmap shift to your team","scenario":"You're pausing a feature your team has invested months in to pivot toward a higher-priority bet. Some of them are attached to the original work and morale is fragile.","task":"Write a short message (4-6 sentences) that frames the pivot as forward motion and addresses the 'was our work wasted?' worry head-on.","tips":["Frame the before/after as a sharpening of focus, not a reversal.","Acknowledge the sunk effort honestly before redirecting.","Make the upside of the new direction concrete and near-term."],"focus":["audience","structure","impact"]},
    {"id":"narrative-mid-04","level":"mid","title":"Defend the budget line","scenario":"Finance has flagged your team's tooling budget for cuts. You believe cutting it would slow delivery, but 'it helps productivity' won't survive the review.","task":"Write a 3-5 sentence defense that translates the tool's value into a concrete number leadership can feel.","tips":["Convert the tool's benefit into hours, deals, or dollars.","Show the cost of removing it, not just the cost of keeping it.","Anticipate 'can't the team work around it?' and answer."],"focus":["precision","impact"]},
    {"id":"narrative-mid-05","level":"mid","title":"Win over the skeptical stakeholder","scenario":"A senior stakeholder in another org doubts your proposed process change will help and worries it'll disrupt their reporting. Their sign-off is needed to proceed.","task":"Write a 4-5 sentence pitch that names their specific worry first, then makes the before/after case.","tips":["Start by voicing their concern in their own terms.","Show you've protected what they care about.","Make the gap you're closing concrete and shared."],"focus":["audience","impact"]},
    {"id":"narrative-mid-06","level":"mid","title":"Make the case for on-call relief","scenario":"Your engineers are burning out on a brutal on-call rotation. You want to fund a reliability sprint, but leadership sees it as 'internal work' with no customer value.","task":"Write a 4-6 sentence pitch that reframes reliability work as customer-facing and stakes-laden.","tips":["Translate 'tech debt' into outages, churn, or response time.","Frame the before/after for both customers and the team.","Pre-empt 'this doesn't ship features' with the cost of not doing it."],"focus":["impact","precision"]},
    {"id":"narrative-mid-07","level":"mid","title":"Justify the priority reorder","scenario":"You want to bump a partner integration ahead of a feature your director personally championed. You need to make the swap without making it feel like a rejection of their idea.","task":"Write a 3-5 sentence case that frames the reorder as sequencing, not cancellation, with concrete stakes.","tips":["Keep their idea alive in the framing — 'after this, not instead of'.","Make the time-sensitivity of the swap concrete.","Disarm 'why now?' with a dated window or dependency."],"focus":["structure","audience"]},
    {"id":"narrative-mid-08","level":"mid","title":"Persuade a peer to share a resource","scenario":"You need three weeks of a specialist who reports to a peer manager. They're worried lending the person will derail their own commitments.","task":"Write a 4-5 sentence ask that frames the loan as a trade, not a favor, and pre-empts their derailment worry.","tips":["Name what you'll give back or de-risk for them.","Bound the ask precisely — duration and scope.","Voice the 'this will slip my work' fear and answer it."],"focus":["concision","audience"]},
    {"id":"narrative-mid-09","level":"mid","title":"Rally the team behind a hard quarter","scenario":"Targets just got raised and the team is demoralized before the quarter even starts. You need them to buy in rather than quietly check out.","task":"Write a 4-6 sentence message that frames the stretch as winnable and makes the payoff concrete.","tips":["Acknowledge the difficulty without dwelling in it.","Frame a clear before/after of what success unlocks for them.","Name the 'this is impossible' objection and reshape it into a plan."],"focus":["audience","impact"]},
    {"id":"narrative-mid-10","level":"mid","title":"Sell a process change across teams","scenario":"You want three teams to adopt a unified code-review standard. Each team has its own way and sees standardization as bureaucracy.","task":"Write a 4-5 sentence pitch that frames the standard as removing friction, not adding it, with a concrete before/after.","tips":["Lead with the cross-team pain the standard removes.","Quantify the cost of the current inconsistency.","Pre-empt 'this slows us down' with where it speeds things up."],"focus":["structure","impact"]},
    {"id":"narrative-mid-11","level":"mid","title":"Pitch the contractor budget","scenario":"You want to bring on two contractors to clear a backlog before a launch. Your boss prefers permanent hires and is wary of 'temporary fixes'.","task":"Write a 3-5 sentence pitch that frames contractors as the right tool for a time-boxed gap and answers the 'why not permanent?' objection.","tips":["Make the time-bounded nature of the need explicit.","Put a concrete cost on missing the launch window.","Address the permanent-vs-temporary worry directly."],"focus":["precision","impact"]},
    {"id":"narrative-mid-12","level":"mid","title":"Reframe a missed target","scenario":"Your team missed a quarterly goal. In the next leadership review you want to make the case for staying the course rather than scrapping the strategy.","task":"Write a 4-6 sentence narrative that frames the miss as a learning curve toward a known destination, with concrete evidence.","tips":["Frame where you were, where you are, and where the trend points.","Use a real leading indicator, not just the lagging miss.","Pre-empt 'the strategy isn't working' with what is moving."],"focus":["structure","impact"]},
    {"id":"narrative-mid-13","level":"mid","title":"Build buy-in for a reorg","scenario":"You're restructuring your team into two pods. People are anxious about new reporting lines and whether their work changes. You need them on board before it's announced widely.","task":"Write a 4-6 sentence message that frames the reorg as solving a real problem they feel, and disarms the 'what happens to me?' fear.","tips":["Anchor the change in a pain the team already complains about.","Frame the before/after of how their day gets better.","Name the personal-uncertainty objection and give reassurance."],"focus":["audience","clarity"]},
    {"id":"narrative-mid-14","level":"mid","title":"Win a cross-functional partner","scenario":"You need marketing to commit launch support for your team's release, but they're swamped and your release isn't on their radar. You're pitching their lead.","task":"Write a 4-5 sentence pitch that frames the launch as a shared win and makes the upside concrete for their goals.","tips":["Connect your release to a metric they're measured on.","Make the cost of an unsupported launch concrete.","Pre-empt 'we don't have bandwidth' with a scoped, light ask."],"focus":["audience","concision"]},
    {"id":"narrative-mid-15","level":"mid","title":"Justify killing a project","scenario":"You want to shut down an initiative your own team built, because the data says it isn't paying off. Two reports are emotionally invested in keeping it alive.","task":"Write a 4-6 sentence case that frames stopping as a smart reallocation and addresses the team's attachment honestly.","tips":["Lead with the recommendation, then the evidence.","Frame the freed-up capacity as where the win moves.","Voice 'but we worked so hard on this' and answer with respect."],"focus":["impact","audience"]},
    {"id":"narrative-mid-16","level":"mid","title":"Push back on an unrealistic deadline","scenario":"Your director set a launch date your team can't hit without cutting corners. You need to renegotiate without sounding like you're making excuses.","task":"Write a 3-5 sentence case that frames the trade-off concretely and offers a credible alternative.","tips":["Make the quality-vs-speed trade-off specific, not abstract.","Offer a dated alternative or a reduced scope, not just 'no'.","Pre-empt 'the team isn't pushing hard enough' with the real constraint."],"focus":["precision","impact"]},
    {"id":"narrative-mid-17","level":"mid","title":"Sell a tooling migration to your team","scenario":"You want your team to migrate off a familiar tool to a better one. They dread the disruption and don't see why the current setup is a problem.","task":"Write a 4-5 sentence pitch that frames the migration's payoff concretely and disarms the 'it works fine now' objection.","tips":["Name the hidden cost of the current tool they've normalized.","Frame the after-state in time they get back.","Scope the migration to lower the perceived risk."],"focus":["impact","audience"]},
    {"id":"narrative-mid-18","level":"mid","title":"Make the case for a training budget","scenario":"You want to send three of your reports to a costly upskilling program. Leadership questions the ROI and whether they'll just leave afterward.","task":"Write a 4-5 sentence pitch that frames the investment with concrete returns and answers the 'they'll leave' worry.","tips":["Tie the skill gap to a real delivery bottleneck.","Make the cost of NOT training concrete.","Disarm the retention objection with the bigger cost of stagnation."],"focus":["impact","precision"]},
    {"id":"narrative-mid-19","level":"mid","title":"Get a peer to adopt your standard","scenario":"You and a peer manager run parallel teams with incompatible deployment practices, causing repeated integration failures. You want them to adopt yours.","task":"Write a 4-5 sentence pitch that frames the alignment as mutual relief and pre-empts the 'why ours, not yours?' tension.","tips":["Anchor in the shared failures both teams feel.","Frame the standard as ending a recurring fire-drill.","Show flexibility on the parts that don't matter to win the parts that do."],"focus":["audience","structure"]},
    {"id":"narrative-mid-20","level":"mid","title":"Pitch a hiring freeze exception","scenario":"There's a company-wide hiring freeze, but a critical role on your team just opened and the gap is creating real risk. You're asking your VP for an exception.","task":"Write a 3-5 sentence ask that frames the exception as risk mitigation and pre-empts the 'everyone wants an exception' pushback.","tips":["Make the specific risk of the gap concrete and urgent.","Distinguish this role from a general 'nice to have'.","Acknowledge the freeze's logic before asking to bend it."],"focus":["precision","impact"]},
    {"id":"narrative-mid-21","level":"mid","title":"Convince your team to drop a beloved ritual","scenario":"Your team loves a long-standing weekly meeting that's lost its value and eats hours. You want to cut it but they're attached to the social side.","task":"Write a 3-5 sentence case that frames the change as reclaiming time and protects what they actually value.","tips":["Name the real cost of the meeting in hours per person.","Frame the after-state — what they do with the time back.","Disarm 'but we'll lose connection' with a lighter replacement."],"focus":["concision","audience"]},
    {"id":"narrative-mid-22","level":"mid","title":"Make the case for slowing down","scenario":"Leadership wants your team to ship faster, but you believe the current pace is causing rework that's actually slowing delivery. You need to argue for a temporary slowdown.","task":"Write a 4-6 sentence case that frames slowing as a path to going faster, with concrete evidence of the rework cost.","tips":["Quantify the rework the current pace is generating.","Frame the before/after as net throughput, not raw speed.","Pre-empt 'this sounds like an excuse to ease off'."],"focus":["impact","structure"]},
    {"id":"narrative-mid-23","level":"mid","title":"Persuade a stakeholder to wait","scenario":"A demanding internal customer wants their feature now, but delivering it this sprint would destabilize a release your team is mid-flight on. You need them to accept a delay.","task":"Write a 3-5 sentence message that frames the wait as protecting their outcome and disarms the 'you always deprioritize us' reaction.","tips":["Frame the delay around what they ultimately want — a stable feature.","Give a concrete, dated commitment for delivery.","Acknowledge the pattern they feel before reassuring."],"focus":["audience","clarity"]},
    {"id":"narrative-mid-24","level":"mid","title":"Pitch the automation investment","scenario":"Your team spends hours each week on manual deploys. You want to fund an automation project, but it competes with feature work leadership wants prioritized.","task":"Write a 4-5 sentence pitch that frames the automation's payoff in recovered capacity and answers 'features matter more'.","tips":["Convert the manual toil into engineer-weeks lost per quarter.","Frame the after-state as more feature capacity, not less.","Pre-empt the trade-off objection by showing it's not either/or for long."],"focus":["impact","precision"]},
    {"id":"narrative-mid-25","level":"mid","title":"Unite two teams on a shared goal","scenario":"Your team and a partner team have been optimizing for different metrics, pulling in opposite directions on a joint product. You're convening both leads to align on one north star.","task":"Write a 4-6 sentence framing that makes the cost of misalignment concrete and pitches a shared goal both teams can own.","tips":["Make the current tug-of-war's cost vivid and shared.","Frame the after-state where both teams win together.","Pre-empt 'this favors your metric over ours' with a genuinely joint goal."],"focus":["structure","audience","impact"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-mid-01","level":"mid","title":"The missed-number 1:1","scenario":"One of your senior reports has missed their quarterly target for the second quarter running, and you've been softening it in past check-ins. In your next 1:1 you need to name the pattern directly and agree on a turnaround plan.","task":"Open the 1:1 with 3-5 sentences that state the pattern plainly, give the concrete impact, and end with one clear ask.","tips":["Lead with the pattern, not five minutes of warm-up.","Use behavior then impact then ask — keep it about the work.","Name a specific, doable next step, not 'try harder'."],"focus":["precision","clarity"],"placeholder":"I want to be straight with you about this quarter's numbers…"},
    {"id":"hard-mid-02","level":"mid","title":"No promotions this cycle","scenario":"Your team expected at least one promotion this review cycle, but budget froze the band and nobody on your team is moving up. You need to tell the team in standup without false hope.","task":"Write a 4-6 sentence message that delivers the news early, explains it honestly, and gives the team something real to hold onto.","tips":["State 'no promotions this cycle' before the reasoning.","Don't blame 'them upstairs' — own the message.","Offer what you can actually influence next cycle."],"focus":["clarity","impact"]},
    {"id":"hard-mid-03","level":"mid","title":"The cancelled project","scenario":"Leadership has killed a six-month project your team poured itself into. The team finds out from you this afternoon and morale is fragile.","task":"Write a 4-6 sentence announcement that breaks the news cleanly, honours the work, and redirects the team forward.","tips":["Headline first: the project is cancelled.","Acknowledge the effort without pretending it's fine.","Point to where their work and energy go next."],"focus":["clarity","impact","audience"]},
    {"id":"hard-mid-04","level":"mid","title":"Declining a peer manager","scenario":"A peer manager asks you to lend two of your engineers to their at-risk release for three weeks. You can't spare them without sinking your own deadline.","task":"Write a 3-5 sentence reply that says no clearly, gives one honest reason, and keeps the peer relationship intact.","tips":["Lead with the no — don't bury it under sympathy.","One real reason beats a stack of excuses.","Offer a smaller alternative only if it's genuine."],"focus":["clarity","concision"],"placeholder":"I wish I could help here, but I can't pull Priya and Dan without…"},
    {"id":"hard-mid-05","level":"mid","title":"Telling your boss the date slips","scenario":"The launch you committed to your VP for the 15th is going to slip by two weeks. You've known for a few days and need to tell them before they hear it elsewhere.","task":"Write a 3-5 sentence message that leads with the new date, explains the cause briefly, and states what you're doing about it.","tips":["Put the new date in the first sentence.","Cause in one line — no defensive essay.","Show the recovery plan, not just the problem."],"focus":["clarity","structure"]},
    {"id":"hard-mid-06","level":"mid","title":"Denying the WFH request","scenario":"A report asks to go fully remote permanently, but their role requires onsite lab work three days a week and you can't approve it.","task":"Write a 3-5 sentence response that declines clearly, gives the real constraint, and leaves the person feeling respected.","tips":["Say no to the request, yes to the person.","Anchor the no in the role's actual requirement.","Offer what flexibility you can genuinely give."],"focus":["clarity","audience"]},
    {"id":"hard-mid-07","level":"mid","title":"Two reports at war","scenario":"Two of your reports have been sniping at each other in meetings and it's derailing the team. You're sitting them both down to address it directly.","task":"Write a 4-6 sentence opening that names the behavior you've observed, its impact on the team, and what you need from both of them.","tips":["Describe the behavior, don't assign villains.","State the team-level impact, not just your annoyance.","End with a concrete expectation for going forward."],"focus":["precision","impact"]},
    {"id":"hard-mid-08","level":"mid","title":"The underperformer who tries hard","scenario":"A well-liked report works long hours but consistently delivers below the bar, and you've avoided the conversation because they care so much. It's now affecting the team's output.","task":"Write 4-6 sentences that separate effort from results, name the gap specifically, and set a clear expectation.","tips":["Acknowledge the effort, then be honest about results.","Point to specific work, not a vague 'quality' label.","Make the bar concrete and the next step doable."],"focus":["precision","clarity"]},
    {"id":"hard-mid-09","level":"mid","title":"Reversing your own decision","scenario":"You greenlit a new workflow last month; it's clearly failing and you're rolling it back. The team adapted to it and will be frustrated by another change.","task":"Write a 3-5 sentence message that owns the call, states the rollback, and explains what you learned.","tips":["Own it in the first sentence — no passive voice.","Be clear it's reverting, effective when.","Frame the lesson without grovelling."],"focus":["clarity","structure"]},
    {"id":"hard-mid-10","level":"mid","title":"The team missed the deadline","scenario":"Your team shipped a key deliverable a week late and a sister team was blocked waiting on it. You're writing to that team's lead to own the miss.","task":"Write a 3-5 sentence note that takes responsibility, states the impact honestly, and commits to a concrete fix.","tips":["Own the miss as the manager — don't deflect to your reports.","Name the impact on them specifically.","Close with what changes so it doesn't recur."],"focus":["clarity","impact"]},
    {"id":"hard-mid-11","level":"mid","title":"Passing over the internal favorite","scenario":"You hired externally for a lead role that an internal report openly wanted and assumed they'd get. You need to tell them before the announcement goes out.","task":"Write a 4-6 sentence message that delivers the decision early, gives an honest reason, and shows you're invested in their growth.","tips":["Tell them the outcome before the reasoning.","Be specific about the gap — vague kindness stings more.","Name a real development path forward."],"focus":["clarity","audience"]},
    {"id":"hard-mid-12","level":"mid","title":"Pushing back on scope","scenario":"Your director keeps adding features to a sprint that's already full, risking the whole release. You need to push back without sounding like you can't deliver.","task":"Write a 3-5 sentence reply that states the trade-off plainly and asks for a priority call.","tips":["Lead with the constraint, then the trade-off.","Frame it as a choice for them to make, not a complaint.","Give the options in concrete terms."],"focus":["clarity","precision"]},
    {"id":"hard-mid-13","level":"mid","title":"The hygiene conversation","scenario":"A report's persistent lateness to client calls has started embarrassing the team in front of customers. You've let it slide twice and need to address it now.","task":"Write a 3-5 sentence opening that names the specific behavior, its concrete impact, and the change you expect.","tips":["State the exact pattern, with examples ready.","Make the impact tangible — name the client moment.","Set a clear, non-negotiable expectation."],"focus":["precision","clarity"]},
    {"id":"hard-mid-14","level":"mid","title":"No raises this year","scenario":"Comp is frozen company-wide and your team has been waiting on merit increases. You're addressing it in a team meeting before the rumor mill does.","task":"Write a 4-6 sentence message that delivers the freeze plainly, explains what's true, and avoids promises you can't keep.","tips":["State the freeze before the context.","Be honest about what you do and don't know.","Don't dangle a maybe to soften it."],"focus":["clarity","impact"]},
    {"id":"hard-mid-15","level":"mid","title":"Declining the stretch project","scenario":"An eager junior report asks to lead a high-visibility project they're not ready for, and you need to decline without crushing their ambition.","task":"Write a 3-5 sentence response that says no to the ask, affirms the person, and offers a real stepping stone.","tips":["Decline the specific ask directly.","Tie the no to readiness, not worth.","Offer a concrete smaller stretch instead."],"focus":["audience","clarity"]},
    {"id":"hard-mid-16","level":"mid","title":"The reorg lands on your team","scenario":"A reorg moves two of your reports under a different manager next month. They'll feel destabilized and you have to deliver it before the org chart drops.","task":"Write a 4-6 sentence message that states the change clearly, explains the why, and steadies the two affected reports.","tips":["Lead with the change and the effective date.","Give the rationale without corporate fog.","Acknowledge the disruption honestly."],"focus":["clarity","audience"]},
    {"id":"hard-mid-17","level":"mid","title":"Owning a bad hire","scenario":"A hire you championed isn't working out and the team has been carrying them. You're acknowledging the misjudgment to your skip-level while proposing a plan.","task":"Write a 3-5 sentence update that owns the call, states the current reality, and lays out next steps.","tips":["Take the hiring decision on yourself.","State where things actually stand, no spin.","Propose a clear path, not just a confession."],"focus":["clarity","structure"]},
    {"id":"hard-mid-18","level":"mid","title":"Killing a report's pet idea","scenario":"A report has been quietly building a side tool they're proud of, but it duplicates an existing system and you need them to stop and refocus.","task":"Write a 3-5 sentence message that declines the direction, respects the initiative, and redirects clearly.","tips":["Say no to the work, yes to the drive behind it.","Give the real reason — duplication, not 'no time'.","Point them at where that energy is needed."],"focus":["clarity","audience"]},
    {"id":"hard-mid-19","level":"mid","title":"The PIP conversation opener","scenario":"After months of clear feedback, a report's performance hasn't improved and you're moving to a formal plan. You need to open that conversation without ambiguity.","task":"Write a 4-6 sentence opening that states the seriousness plainly, recaps the specific gaps, and frames the plan as a real chance to recover.","tips":["Don't soften it into a routine check-in — name the stakes.","Recap concrete behaviors, not a character verdict.","Be clear this is a path to improve, with support."],"focus":["clarity","precision","impact"]},
    {"id":"hard-mid-20","level":"mid","title":"Bad news from above","scenario":"Leadership cut your headcount request and you have to deliver the no to a report who was counting on a new teammate to ease their load.","task":"Write a 3-5 sentence message that delivers the no clearly, owns it as the manager, and addresses the workload reality.","tips":["State the outcome up front — the role isn't coming.","Don't hide behind 'leadership said no'.","Engage the real problem: their load."],"focus":["clarity","impact"]},
    {"id":"hard-mid-21","level":"mid","title":"Correcting in the moment","scenario":"In a team meeting a report confidently states something wrong that's about to send the group down a costly path. You need to correct it on the spot without humiliating them.","task":"Write 2-3 sentences that redirect the room clearly while keeping the report's standing intact.","tips":["Fix the facts without making it personal.","Be crisp — the room is watching the clock.","Leave the person a graceful way to stay engaged."],"focus":["concision","audience"]},
    {"id":"hard-mid-22","level":"mid","title":"The favoritism perception","scenario":"A report tells you they feel you favor a teammate and it's hurting their motivation. You need to respond honestly rather than defensively.","task":"Write a 3-5 sentence response that takes the concern seriously, states your view plainly, and commits to a concrete change.","tips":["Acknowledge before you explain — don't lead with defense.","Be honest about what's true and what isn't.","Name one tangible thing you'll do differently."],"focus":["audience","clarity"]},
    {"id":"hard-mid-23","level":"mid","title":"Saying no to your boss's pet request","scenario":"Your VP casually asks your team to take on a side initiative that would derail your committed roadmap. Saying yes is the easy path; it's the wrong one.","task":"Write a 3-5 sentence reply that declines the add, names the trade-off, and offers a decision point.","tips":["Lead with the conflict, not with flattery.","Make the cost of yes concrete and specific.","Hand them the choice rather than just refusing."],"focus":["clarity","precision"]},
    {"id":"hard-mid-24","level":"mid","title":"The quality slipped on your watch","scenario":"A customer escalation traces back to a corner your team cut under deadline pressure that you approved. You're addressing it with the team without scapegoating anyone.","task":"Write a 4-6 sentence message that owns the call, names what went wrong specifically, and sets the new standard.","tips":["Take the decision on yourself, not the individual.","Be specific about the miss, not abstractly disappointed.","Make the corrected standard clear and concrete."],"focus":["clarity","precision","impact"]},
    {"id":"hard-mid-25","level":"mid","title":"Ending the always-yes pattern","scenario":"You've said yes to so many cross-team asks that your own team is buried. You need to send one message resetting expectations with the peers who keep pulling on you.","task":"Write a 4-6 sentence note that names the pattern, states what you'll now protect, and offers a clear path for real priorities.","tips":["Be plain that the default is changing.","Don't apologize your way through it.","Give peers a concrete intake path for genuine needs."],"focus":["clarity","structure"]}
  ],
  "putting-it-together": [
    {"id":"capstone-mid-01","level":"mid","title":"Team reorg announcement","scenario":"You manage a 14-person team that's splitting into two squads next quarter to support a new product area. Some people are nervous about who reports to whom and whether this signals layoffs. You're writing the announcement that goes to the whole team Monday morning.","task":"Write the announcement (6–9 sentences) that leads with the change, explains the why, and names what is and isn't changing for people.","tips":["First sentence: the structural change in plain terms.","Name the rationale before the mechanics.","Pre-empt the fear — say explicitly whether jobs are at risk.","Close with the next step and where to ask questions."],"focus":["structure","audience","clarity"]},
    {"id":"capstone-mid-02","level":"mid","title":"Proposal to leadership","scenario":"Your team is drowning in support tickets and you want budget for two contractors for six months. Leadership funds things that show ROI, not things that sound hard. You have data: ticket volume up 40%, response time slipping past SLA.","task":"Write a proposal (7–10 sentences) that leads with the ask and the payoff, then backs it with the evidence and the cost.","tips":["Open with the ask and the result it buys, not the backstory.","Tie the spend to a number leadership cares about.","State the cost plainly and the cost of doing nothing.","Make approval a single clear yes."],"focus":["impact","structure","precision"]},
    {"id":"capstone-mid-03","level":"mid","title":"Cross-functional decision memo","scenario":"Engineering, design, and marketing each want a different launch date for a feature. As the owning manager you've decided on March 15, accepting a scoped-down v1. You're writing the memo that records the decision for all three teams.","task":"Write a decision memo (6–9 sentences) that states the decision up front, names the tradeoff, and assigns the next actions.","tips":["Lead with the decision and the date — no suspense.","Acknowledge what each team gives up, briefly.","Group the rationale under one governing reason.","End with who owns what by when."],"focus":["structure","precision","clarity"]},
    {"id":"capstone-mid-04","level":"mid","title":"Performance feedback message","scenario":"A strong report has started missing handoffs, leaving two teammates blocked twice this sprint. You want to correct it without deflating someone you value. You're writing the message ahead of your 1:1.","task":"Write the message (5–8 sentences) that names the specific behavior, states the impact, and ends with a clear ask — calibrated to keep them engaged.","tips":["Describe what happened, not a character label.","Make the impact concrete: who was blocked, how often.","Signal you value them without burying the correction.","Close with one doable change, not 'do better'."],"focus":["precision","audience","impact"]},
    {"id":"capstone-mid-05","level":"mid","title":"Rally after a setback","scenario":"Your team's flagship feature shipped, then had to be rolled back after a production incident embarrassed a big customer. Morale is low and people feel they failed. You're writing the team message the morning after the rollback.","task":"Write the message (6–9 sentences) that names reality honestly, reframes the path forward, and gives the team one concrete next step.","tips":["Don't sugarcoat — name what happened plainly.","Separate the setback from the people; no blame.","Give them a reason the situation is recoverable.","End with one specific action for today, not a pep slogan."],"focus":["audience","impact","clarity"]},
    {"id":"capstone-mid-06","level":"mid","title":"Escalation to your boss","scenario":"A dependency from another team is three weeks late and will blow your launch date. You've tried to resolve it directly and it hasn't moved. You need your director to intervene with the other team's leader.","task":"Write the escalation (5–8 sentences) that leads with what you need from your boss, states the facts, and proposes the intervention.","tips":["First sentence: the specific help you're asking for.","Give just the facts that justify escalating — dates, attempts made.","Show you tried before escalating.","Propose the exact intervention, don't just complain."],"focus":["impact","concision","precision"]},
    {"id":"capstone-mid-07","level":"mid","title":"Leadership status update","scenario":"Your monthly update goes to your VP. This month: roadmap on track, one hire fell through, and a risk is emerging that a key integration may slip. You tend to over-explain and bury the risk at the bottom.","task":"Write the update (6–9 sentences) that surfaces the risk early, groups status by good/risk/ask, and stays tight.","tips":["Lead with the headline status, then the risk — don't hide it.","Group the news; don't interleave wins and problems randomly.","Quantify the risk's impact and your mitigation.","Cut anything the VP wouldn't act on."],"focus":["structure","concision","precision"]},
    {"id":"capstone-mid-08","level":"mid","title":"Saying no to a stakeholder","scenario":"A peer manager keeps adding 'small' requests that pull two of your engineers off committed work. You need to decline the latest one without damaging the relationship or looking unhelpful to your shared boss, who's cc'd.","task":"Write the reply (5–8 sentences) that declines clearly, explains the tradeoff in their terms, and offers a real alternative.","tips":["Say no early and unambiguously — no maybe-that-means-no.","Frame the tradeoff around shared priorities, not your inconvenience.","Offer a genuine alternative or a path to yes.","Keep the tone collaborative; the boss is reading."],"focus":["clarity","audience","concision"]},
    {"id":"capstone-mid-09","level":"mid","title":"Promotion case for a report","scenario":"You're nominating a report for promotion. The committee reads dozens of these and rewards evidence of scope and impact, not adjectives. You have specifics: led the billing migration, mentored two juniors, owned an outage postmortem.","task":"Write the promotion case (7–10 sentences) that leads with the verdict, then proves scope and impact with concrete evidence.","tips":["Open with the recommendation and the level, plainly.","Replace 'great' and 'strong' with what they actually did.","Tie each example to business impact.","Match the register the committee expects — confident, evidence-led."],"focus":["precision","impact","structure"]},
    {"id":"capstone-mid-10","level":"mid","title":"Kill-the-project recommendation","scenario":"A project your team championed isn't working — adoption is flat after two quarters and the maintenance cost is rising. You've concluded it should be sunset, even though it was your idea. You're writing the recommendation to your director.","task":"Write the recommendation (6–9 sentences) that states the call up front, owns the reversal, and frames the freed-up capacity as the upside.","tips":["Lead with the recommendation to sunset — don't bury it in nuance.","Show the evidence that changed your mind.","Own the call without excessive apology.","Reframe the wind-down around what the team gains."],"focus":["clarity","impact","precision"]},
    {"id":"capstone-mid-11","level":"mid","title":"Onboarding a new manager peer","scenario":"A new manager just joined and will co-own a shared workflow with your team. There's history and unwritten rules they need to know without feeling lectured. You're writing the welcome-and-orient message.","task":"Write the message (6–9 sentences) that leads with the working relationship you want, conveys the key context, and sets up a first conversation.","tips":["Open warm but lead with how you'll work together.","Surface the two or three things they actually need to know.","Frame norms as 'how it works here,' not rules to obey.","End with a concrete next step to meet."],"focus":["audience","structure","clarity"]},
    {"id":"capstone-mid-12","level":"mid","title":"Deadline-slip notification","scenario":"A committed deliverable will land a week late because of a discovery your team made mid-build. Three downstream teams are planning around the original date. You're writing the message that resets expectations.","task":"Write the notification (5–8 sentences) that states the new date first, explains the cause concisely, and tells each downstream team what to do.","tips":["Lead with the new date, not the apology.","Explain the cause in one or two sentences — no saga.","Tell readers exactly how it affects their planning.","Project control, not panic."],"focus":["concision","clarity","precision"]},
    {"id":"capstone-mid-13","level":"mid","title":"Budget-cut allocation","scenario":"Your department budget was cut 15% and you must decide what your team stops doing. You've chosen to pause a research initiative rather than cut headcount. You're writing to your team to explain the choice.","task":"Write the message (6–9 sentences) that states what's stopping, explains the principle behind the choice, and reassures on what's protected.","tips":["Lead with the concrete change: what stops.","Name the principle that drove the tradeoff.","Say clearly what is safe so rumor doesn't fill the gap.","Be honest about the cost without catastrophizing."],"focus":["clarity","audience","structure"]},
    {"id":"capstone-mid-14","level":"mid","title":"Pushback on a leadership directive","scenario":"Your VP wants your team to adopt a new process you believe will slow delivery by weeks. You want to register a substantive objection without being insubordinate. You're writing the reply.","task":"Write the reply (6–9 sentences) that leads with your concern and its cost, offers evidence, and proposes an alternative path.","tips":["State the concern early and specifically — not vague unease.","Quantify the cost you're worried about.","Disagree on substance, stay aligned on the goal.","Bring an alternative, not just resistance."],"focus":["impact","precision","audience"]},
    {"id":"capstone-mid-15","level":"mid","title":"Incident postmortem summary","scenario":"Your team caused a four-hour outage. The blameless postmortem is done; now you owe leadership a summary. They want to know what happened, what you've fixed, and whether it can recur — not a 12-page timeline.","task":"Write the summary (6–9 sentences) that leads with impact and root cause, states the fix, and addresses recurrence risk.","tips":["Open with what broke and who was affected.","Give the root cause in one precise sentence.","State concrete fixes already shipped or scheduled.","Answer the unspoken question: can this happen again?"],"focus":["precision","structure","concision"]},
    {"id":"capstone-mid-16","level":"mid","title":"Quarterly goals to the team","scenario":"You're setting your team's three priorities for the quarter after a noisy planning cycle full of competing asks. People are unsure what actually matters now. You're writing the message that makes the priorities stick.","task":"Write the message (6–9 sentences) that names the three priorities crisply, says what's explicitly deprioritized, and connects it to the bigger goal.","tips":["Lead with the three priorities, numbered and concrete.","Say what you're NOT doing — that's what makes it real.","Tie each to the outcome it serves.","Cut hedging that makes everything sound equally urgent."],"focus":["clarity","structure","concision"]},
    {"id":"capstone-mid-17","level":"mid","title":"Mediating a team conflict","scenario":"Two senior reports clashed publicly in a design review, and the tension is spreading. You've talked to each separately and reached a path forward. You're writing the message to both that resets the working norm.","task":"Write the message (6–9 sentences) that names the situation without taking sides, states the agreed norm, and points to a shared goal.","tips":["Acknowledge the friction plainly without assigning blame.","State the concrete behavior you expect going forward.","Keep both people's standing intact.","Anchor on the shared outcome you all want."],"focus":["audience","precision","clarity"]},
    {"id":"capstone-mid-18","level":"mid","title":"Hiring case to your boss","scenario":"You want approval to open a senior role on your team. Your director will ask why now, why senior, and why not redistribute the work. You have the answers and need to make the case in writing first.","task":"Write the case (6–9 sentences) that leads with the ask, pre-empts the three objections, and states the cost of not hiring.","tips":["Open with the specific role and level you want to open.","Anticipate and answer the obvious pushback up front.","Quantify what the gap is costing now.","Make the yes easy and the timeline clear."],"focus":["impact","structure","precision"]},
    {"id":"capstone-mid-19","level":"mid","title":"Scope-creep reset with a client","scenario":"An internal client keeps expanding a project your team committed to, and the original deadline is now impossible without more scope or time. You manage the delivery team and must reset the agreement professionally.","task":"Write the message (6–9 sentences) that restates the original scope, names what's changed, and offers a clear choose-one tradeoff.","tips":["Lead with the recommitment to a shared outcome.","Make the scope change visible and specific.","Offer a concrete tradeoff: cut scope, move date, or add resource.","Stay firm and collaborative, not defensive."],"focus":["precision","clarity","audience"]},
    {"id":"capstone-mid-20","level":"mid","title":"Defending the team's work","scenario":"Another department blamed a missed company target on your team in a leadership meeting. The claim is partly unfair. Your director asked you to respond in writing to the leadership thread, with the other manager cc'd.","task":"Write the response (6–9 sentences) that corrects the record with facts, owns your team's real part, and redirects to the fix.","tips":["Lead with the correction, calmly and factually.","Concede what's legitimately yours — it buys credibility.","Use specifics, not adjectives, to counter the claim.","Pivot from blame to the path forward."],"focus":["precision","impact","audience"]},
    {"id":"capstone-mid-21","level":"mid","title":"Delegating a stretch project","scenario":"You're handing a high-visibility project to a report who's ready to grow but hasn't led at this level. You want to set them up to own it without micromanaging or under-supporting. You're writing the handoff message.","task":"Write the message (6–9 sentences) that frames the opportunity, defines the outcome and guardrails, and clarifies your role.","tips":["Lead with what they own and why it matters.","Define success and the boundaries, not the steps.","Be explicit about where you'll back them up.","Convey confidence — this is a vote of trust."],"focus":["clarity","audience","structure"]},
    {"id":"capstone-mid-22","level":"mid","title":"Reversing your own decision","scenario":"Two weeks ago you told the team you'd adopt a new tool. New information shows it won't integrate with a critical system. You need to reverse course without looking indecisive or eroding trust.","task":"Write the message (5–8 sentences) that states the reversal, explains what changed, and reaffirms the decision-making you'll keep using.","tips":["Lead with the new decision, clearly labeled as a change.","Show the new fact that justifies the reversal.","Own it briefly — credibility comes from candor, not apology.","Reassure that the process was sound."],"focus":["clarity","precision","audience"]},
    {"id":"capstone-mid-23","level":"mid","title":"Cross-team launch alignment","scenario":"Your launch depends on three teams hitting the same date, and right now they each assume different things about who does what. You're the owning manager writing the message that locks alignment before the kickoff.","task":"Write the message (6–9 sentences) that states the shared date and goal, assigns each team's deliverable, and names the single decision owner.","tips":["Open with the one date and outcome everyone is committing to.","List each team's deliverable unambiguously.","Name who decides when teams disagree.","Cut narrative — this is a coordination contract."],"focus":["structure","precision","concision"]},
    {"id":"capstone-mid-24","level":"mid","title":"Coaching a high performer who's stuck","scenario":"Your best engineer is excellent technically but their blunt review comments are alienating teammates, and two have complained. You want to raise it in a way that lands with someone who values directness and evidence.","task":"Write the message (6–9 sentences) that names the pattern with specifics, connects it to their own goals, and proposes a concrete change.","tips":["Use concrete examples, not 'people find you harsh.'","Frame it through what they care about — impact and influence.","Be direct; they'll respect that more than cushioning.","End with one specific behavior to try."],"focus":["precision","audience","impact"]},
    {"id":"capstone-mid-25","level":"mid","title":"Year-end team narrative","scenario":"You're writing the end-of-year wrap to your team after a hard but productive year — a reorg, a tough launch, real wins. Leadership will also see it. You want it honest, motivating, and not a list of bullet points nobody reads.","task":"Write the message (7–10 sentences) that leads with the through-line of the year, names two or three real wins with specifics, and points the team forward.","tips":["Open with the one story the year tells — not 'it was busy.'","Pick a few concrete wins over an exhaustive list.","Acknowledge the hard parts honestly; it earns the optimism.","Calibrate for both audiences: heartfelt for the team, credible for leadership."],"focus":["impact","structure","audience"]}
  ],
};
